                      </p>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="asesorConfirmPassword">
                        Confirmar Contraseña{" "}
                        <span className="text-red-500">*</span>
                      </Label>
                      <div className="relative">
                        <Input
