                        )}
                      </Button>
                    </div>
                  </form>
                </DialogContent>
              </Dialog>
            </CardContent>
          </Card>

          {/* Crear Campaña */}
          <Card className="hover:shadow-xl transition-all border-2 border-transparent hover:border-purple-200">
            <CardHeader>
              <div className="flex items-center gap-3 mb-2">
                <div className="p-3 bg-purple-100 dark:bg-purple-900 rounded-lg">
                  <Target className="w-6 h-6 text-purple-600 dark:text-purple-400" />
                </div>
                <div>
                  <CardTitle>Crear Campaña</CardTitle>
                  <CardDescription>
                    Lanza una nueva campaña publicitaria
                  </CardDescription>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-muted-foreground mb-4">
                Las campañas te ayudan a generar leads y expandir tu negocio.
                Define objetivos claros y presupuesto para mejores resultados.
              </p>

              <Dialog
                open={campaignDialogOpen}
                onOpenChange={setCampaignDialogOpen}
              >
                <DialogTrigger asChild>
                  <Button className="w-full" size="lg" variant="secondary">
                    <Plus className="w-4 h-4 mr-2" />
                    Nueva Campaña
                  </Button>
                </DialogTrigger>
                <DialogContent className="max-w-md">
                  <DialogHeader>
                    <DialogTitle>Crear Nueva Campaña</DialogTitle>
                    <DialogDescription>
                      Define los parámetros de tu campaña
                    </DialogDescription>
                  </DialogHeader>

                  <form onSubmit={handleCreateCampaign} className="space-y-4">
                    <div className="space-y-2">
                      <Label htmlFor="campaignName">
                        Nombre de la Campaña{" "}
                        <span className="text-red-500">*</span>
                      </Label>
                      <Input
                        id="campaignName"
                        placeholder="Ej: Campaña Verano 2025"
                        value={campaignName}
                        onChange={(e) => setCampaignName(e.target.value)}
                        required
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="campaignBudget">
                        Presupuesto (USD){" "}
                        <span className="text-red-500">*</span>
                      </Label>
                      <Input
                        id="campaignBudget"
                        type="number"
                        placeholder="1000"
                        min="0"
                        step="0.01"
                        value={campaignBudget}
                        onChange={(e) => setCampaignBudget(e.target.value)}
                        required
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="campaignStartDate">
                        Fecha de Inicio <span className="text-red-500">*</span>
                      </Label>
                      <Input
                        id="campaignStartDate"
                        type="date"
                        value={campaignStartDate}
                        onChange={(e) => setCampaignStartDate(e.target.value)}
                        required
                      />
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="campaignDescription">Descripción</Label>
                      <Textarea
                        id="campaignDescription"
                        placeholder="Objetivos y detalles de la campaña..."
                        value={campaignDescription}
                        onChange={(e) => setCampaignDescription(e.target.value)}
                        rows={3}
                      />
                    </div>

                    <div className="flex gap-2 pt-4">
                      <Button
                        type="button"
                        variant="outline"
                        className="flex-1"
                        onClick={() => setCampaignDialogOpen(false)}
                      >
                        Cancelar
                      </Button>
                      <Button
                        type="submit"
                        className="flex-1"
                        disabled={createCampaignMutation.isPending}
                      >
                        {createCampaignMutation.isPending ? (
                          <>
                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            Creando...
                          </>
                        ) : (
                          "Crear Campaña"
                        )}
                      </Button>
                    </div>
                  </form>
                </DialogContent>
              </Dialog>
            </CardContent>
          </Card>
        </div>

        {/* Lists Section */}
        <div className="grid md:grid-cols-2 gap-6">
          {/* Mis Asesores */}
          <Card>
            <CardHeader>
              <CardTitle>Mis Asesores</CardTitle>
              <CardDescription>
                {loadingAsesores
                  ? "Cargando..."
                  : `${asesores?.length || 0} asesor${asesores?.length !== 1 ? "es" : ""} registrado${asesores?.length !== 1 ? "s" : ""}`}
              </CardDescription>
            </CardHeader>
            <CardContent>
              {loadingAsesores ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
                </div>
              ) : asesores.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  <Users className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p className="text-lg font-medium mb-2">
                    No hay asesores registrados
                  </p>
                  <p className="text-sm">
                    Crea tu primer asesor usando el botón "Nuevo Asesor"
                  </p>
                </div>
              ) : (
                <div className="space-y-2">
                  {asesores.slice(0, 5).map((asesor: any) => (
                    <div
                      key={asesor.id}
                      className="p-3 border rounded-lg hover:bg-muted/50 transition-colors flex items-center justify-between group"
                    >
                      <div className="flex-1">
                        <p className="font-medium">{asesor.username}</p>
                        {asesor.email && (
                          <p className="text-xs text-muted-foreground">
                            {asesor.email}
                          </p>
                        )}
                      </div>

                      {/* Botón de eliminar */}
                      <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => {
                            setAsesorToDelete(asesor);
                            setDeleteAsesorDialogOpen(true);
                          }}
                        >
                          <Trash2 className="w-4 h-4 text-destructive" />
                        </Button>
                      </div>
                    </div>
                  ))}
                  {asesores.length > 5 && (
                    <p className="text-xs text-center text-muted-foreground pt-2">
                      +{asesores.length - 5} más
                    </p>
                  )}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Mis Campañas */}
          <Card>
            <CardHeader>
              <CardTitle>Mis Campañas</CardTitle>
              <CardDescription>
                {loadingCampanasStats
                  ? "Cargando..."
                  : `${campanasStats?.total || 0} campaña${campanasStats?.total !== 1 ? "s" : ""} activa${campanasStats?.total !== 1 ? "s" : ""}`}
              </CardDescription>
            </CardHeader>
            <CardContent>
              {loadingCampanas ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
                </div>
              ) : campanas.length === 0 ? (
                <p className="text-sm text-muted-foreground py-4">
                  Aún no has creado campañas. ¡Lanza tu primera campaña arriba!
                </p>
              ) : (
                <div className="space-y-2">
                  {campanas.slice(0, 5).map((campana: any) => (
                    <div
                      key={campana.id}
                      className="p-3 border rounded-lg hover:bg-muted/50 transition-colors"
                    >
                      <p className="font-medium">{campana.nombre}</p>
                      {campana.presupuesto && (
                        <p className="text-xs text-muted-foreground">
                          Presupuesto: ${campana.presupuesto}
                        </p>
                      )}
                    </div>
                  ))}
                  {campanas.length > 5 && (
                    <p className="text-xs text-center text-muted-foreground pt-2">
                      +{campanas.length - 5} más
                    </p>
                  )}
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        {/* Info Section */}
        <Card className="mt-8 border-blue-200 bg-blue-50/50 dark:bg-blue-950/20">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <User className="w-5 h-5" />
              Información de tu cuenta
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid md:grid-cols-2 gap-4 text-sm">
              <div>
                <p className="text-muted-foreground">Usuario</p>
                <p className="font-medium">{user?.username}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Email</p>
                <p className="font-medium">
                  {user?.email || "No especificado"}
                </p>
              </div>
              <div>
                <p className="text-muted-foreground">Rol</p>
                <p className="font-medium capitalize">{user?.role}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Miembro desde</p>
                <p className="font-medium">
                  {user?.createdAt
                    ? new Date(user.createdAt).toLocaleDateString("es-ES")
                    : "N/A"}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Dialog de confirmación de eliminación de asesor */}
      <Dialog
        open={deleteAsesorDialogOpen}
        onOpenChange={setDeleteAsesorDialogOpen}
      >
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>¿Eliminar Asesor?</DialogTitle>
            <DialogDescription>
              Esta acción no se puede deshacer. El asesor "
              {asesorToDelete?.username}" será eliminado permanentemente y ya no
              tendrá acceso al sistema.
            </DialogDescription>
          </DialogHeader>

          <div className="flex gap-2 pt-4">
            <Button
              variant="outline"
              className="flex-1"
              onClick={() => {
                setDeleteAsesorDialogOpen(false);
                setAsesorToDelete(null);
              }}
            >
              Cancelar
            </Button>
            <Button
              variant="destructive"
              className="flex-1"
              onClick={() => {
                if (asesorToDelete) {
                  deleteAsesorMutation.mutate(asesorToDelete.id);
                }
              }}
              disabled={deleteAsesorMutation.isPending}
            >
              {deleteAsesorMutation.isPending ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Eliminando...
                </>
              ) : (
                "Eliminar"
              )}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

shared/utils/brand-display-utils.ts.content:
import { extractBrandsFromCampaign, type BrandInfo } from './multi-brand-utils';

/**
 * Interfaz extendida para información de marca con datos de zona
 */
export interface ExtendedBrandInfo extends BrandInfo {
  zona: string;
}

/**
 * Función mejorada para obtener información de marcas de campañas
 * Compatible con la función existente getCampaignBrandInfo pero con mejor tipado
 */
export function getCampaignBrandInfo(
  data: any,
  campanasComerciales?: any[]
): ExtendedBrandInfo[] {
  // Función helper para extraer marca de cliente (fallback)
  const extractMarcaFallback = (cliente: string): string => {
    const match = cliente.match(/^([A-Z]+)/);
    return match ? match[1] : cliente.split(' ')[0] || 'UNKNOWN';
  };

  if (!campanasComerciales || campanasComerciales.length === 0) {
    // Si no hay datos de campañas comerciales, usar datos básicos
    return [{
      marca: data.marca || extractMarcaFallback(data.cliente),
      zona: data.zona || 'N/A',
      porcentaje: 100
    }];
  }

  // Buscar la campaña correspondiente
  const campana = campanasComerciales.find((c: any) =>
    c.numeroCampana === data.numeroCampana.toString() &&
    c.marca.toLowerCase() === (data.marca || extractMarcaFallback(data.cliente)).toLowerCase() &&
    c.zona === data.zona
  );

  if (!campana) {
    // Si no encuentra la campaña, usar datos de la fila actual
    return [{
      marca: data.marca || extractMarcaFallback(data.cliente),
      zona: data.zona || 'N/A',
      porcentaje: 100
    }];
  }

  // Usar la función existente para extraer marcas y agregar zona
  const brands = extractBrandsFromCampaign(campana, campana.asignacionAutomatica);

  const extendedBrands: ExtendedBrandInfo[] = [];

  // Marca principal
  if (campana.marca) {
    const mainBrand = brands.find(b => b.marca === campana.marca);
    if (mainBrand) {
      extendedBrands.push({
        ...mainBrand,
        zona: campana.zona || 'N/A'
      });
    }
  }

  // Marcas adicionales (2-5) con sus zonas respectivas
  for (let i = 2; i <= 5; i++) {
    const marca = campana[`marca${i}`];
    const zona = campana[`zona${i}`];

    if (marca) {
      const brand = brands.find(b => b.marca === marca);
      if (brand) {
        extendedBrands.push({
          ...brand,
          zona: zona || campana.zona || 'N/A' // Usar zona específica o principal como fallback
        });
      }
    }
  }

  // Si no se encontraron marcas, usar fallback
  if (extendedBrands.length === 0) {
    return [{
      marca: data.marca || extractMarcaFallback(data.cliente),
      zona: data.zona || 'N/A',
      porcentaje: 100
    }];
  }

  return extendedBrands;
}

/**
 * Determina si una campaña tiene asignación automática
 */
export function isAutomaticAssignment(campaignData: any): boolean {
  return campaignData?.asignacionAutomatica === true;
}

/**
 * Genera texto de display para marcas según el modo de asignación
 */
export function getBrandDisplayText(
  brands: ExtendedBrandInfo[],
  isAutomatic: boolean = false,
  includeZones: boolean = false
): string {
  if (!brands || brands.length === 0) {
    return 'Sin marcas';
  }

  if (isAutomatic) {
    // Modo automático: "Marca1, Marca2, Marca3 (AUTO)"
    const marcasStr = brands.map(b => b.marca).join(', ');
    return `${marcasStr} (AUTO)`;
  }

  if (brands.length === 1) {
    // Una sola marca
    const brand = brands[0];
    const zoneInfo = includeZones ? ` - ${brand.zona}` : '';
    return `${brand.marca}${zoneInfo}`;
  }

  // Múltiples marcas con porcentajes
  return brands.map(brand => {
    const zoneInfo = includeZones ? ` - ${brand.zona}` : '';
    return `${brand.marca} (${brand.porcentaje}%)${zoneInfo}`;
  }).join(', ');
}

/**
 * Obtiene estadísticas de marcas para una campaña
 */
export function getBrandStats(brands: ExtendedBrandInfo[]): {
  totalBrands: number;
  totalPercentage: number;
  isValidDistribution: boolean;
  mainBrand: string;
} {
  const totalBrands = brands.length;
  const totalPercentage = brands.reduce((sum, brand) => sum + brand.porcentaje, 0);
  const isValidDistribution = totalPercentage === 100;
  const mainBrand = brands.length > 0 ? brands[0].marca : '';

  return {
    totalBrands,
    totalPercentage,
    isValidDistribution,
    mainBrand
  };
}

server/sync/domain/services/DuplicateDet.content:
import { ProcessedSyncLead, SyncLead } from '../entities/SyncLead';

/**
 * Servicio de dominio para detección de duplicados
 * Contiene la lógica de negocio para identificar leads duplicados
 */
export class DuplicateDetector {

  /**
   * Detecta duplicados en un lote de leads procesados
   */
  detectDuplicatesInBatch(leads: ProcessedSyncLead[]): ProcessedSyncLead[] {
    const phoneMap = new Map<string, ProcessedSyncLead>();
    const metaIdMap = new Map<string, ProcessedSyncLead>();
    const rowNumberMap = new Map<string, ProcessedSyncLead>(); // marca + rowNumber

    const processedLeads: ProcessedSyncLead[] = [];

    for (const lead of leads) {
      const duplicate = this.findDuplicateInBatch(lead, phoneMap, metaIdMap, rowNumberMap);

      if (duplicate) {
        // Marcar como duplicado
        processedLeads.push({
          ...lead,
          isDuplicate: true,
          duplicateOf: duplicate.metaLeadId
        });
      } else {
        // Agregar al mapa para futuras comparaciones
        phoneMap.set(lead.normalizedPhone, lead);
        metaIdMap.set(lead.metaLeadId, lead);

        // Agregar al mapa de números de fila si existe
        if (lead.googleSheetsRowNumber && lead.marca) {
          const rowKey = `${lead.marca.toUpperCase()}_${lead.googleSheetsRowNumber}`;
          rowNumberMap.set(rowKey, lead);
        }

        processedLeads.push({
          ...lead,
          isDuplicate: false
        });
      }
    }

    return processedLeads;
  }

  /**
   * Detecta si un lead es duplicado comparándolo con leads existentes
   */
  detectDuplicatesAgainstExisting(
    newLeads: ProcessedSyncLead[], 
    existingLeads: SyncLead[]
  ): ProcessedSyncLead[] {

    console.log(`🔍 MIGRACIÓN COMPLETA: Verificando ${newLeads.length} leads nuevos contra ${existingLeads.length} existentes`);
    console.log(`🎯 NUEVA LÓGICA: Solo usando googleSheetsRowNumber como criterio de duplicado`);

    // Crear mapa de filas existentes para búsqueda rápida (solo necesitamos esto)
    const existingRowNumbers = new Set(
      existingLeads
        .filter(l => l.googleSheetsRowNumber && l.marca)
        .map(l => `${l.marca.toUpperCase()}_${l.googleSheetsRowNumber}`)
    );

    let duplicatesFound = 0;
    let duplicatesByRow = 0;

    const result = newLeads.map((lead, index) => {
      // 🎯 NUEVA LÓGICA: Solo considerar duplicado por número de fila de Google Sheets
      // Esto permite migrar TODOS los datos, incluso con teléfonos repetidos
      let isDuplicateByRowNumber = false;
      let rowKey = null;
      if (lead.googleSheetsRowNumber && lead.marca) {
        rowKey = `${lead.marca.toUpperCase()}_${lead.googleSheetsRowNumber}`;
        isDuplicateByRowNumber = existingRowNumbers.has(rowKey);
      }

      // ✅ SOLO usar fila como criterio de duplicado para migración completa
      const isDuplicate = isDuplicateByRowNumber;

      if (isDuplicate) {
        duplicatesFound++;
        if (isDuplicateByRowNumber) duplicatesByRow++;

        // Encontrar el lead original para referencia (solo por fila)
        const originalLead = existingLeads.find(l => 
          rowKey && l.googleSheetsRowNumber && l.marca && 
          `${l.marca.toUpperCase()}_${l.googleSheetsRowNumber}` === rowKey
        );

        // 🚨 LOG DETALLADO DE DUPLICADOS
        console.log(`🚨 DUPLICADO POR FILA [${index + 1}/${newLeads.length}]:`);
        console.log(`   Nuevo lead: ${lead.nombre} | Tel: ${lead.normalizedPhone} | Fila: ${lead.googleSheetsRowNumber}`);
        console.log(`   Razón: Row=${isDuplicateByRowNumber} (ya existe esta fila)`);
        if (originalLead) {
          console.log(`   Lead existente: ${originalLead.nombre} | Fila: ${originalLead.googleSheetsRowNumber} | MetaID: ${originalLead.metaLeadId}`);
        }
        console.log(`   RowKey: ${rowKey}`);

        return {
          ...lead,
          isDuplicate: true,
          duplicateOf: originalLead?.metaLeadId
        };
      } else {
        // 📝 LOG DE LEADS NUEVOS (solo primeros 5 para no saturar logs)
        if (index < 5) {
          console.log(`✅ LEAD NUEVO [${index + 1}]: ${lead.nombre} | Tel: ${lead.normalizedPhone} | Fila: ${lead.googleSheetsRowNumber}`);
        }
      }

      return {
        ...lead,
        isDuplicate: false
      };
    });

    console.log(`🎯 MIGRACIÓN COMPLETA - RESUMEN:`);
    console.log(`   📊 Total evaluados: ${newLeads.length}`);
    console.log(`   🚫 Duplicados por fila existente: ${duplicatesByRow}`);
    console.log(`   ✅ Leads nuevos para migrar: ${newLeads.length - duplicatesFound}`);
    console.log(`   📈 Tasa de migración: ${((newLeads.length - duplicatesFound) / newLeads.length * 100).toFixed(1)}%`);

    return result;
  }

  /**
   * Calcula el score de similitud entre dos leads
   */
  calculateSimilarityScore(lead1: ProcessedSyncLead, lead2: ProcessedSyncLead): number {
    let score = 0;
    let maxScore = 0;

    // Comparar teléfono (peso alto)
    maxScore += 40;
    if (lead1.normalizedPhone === lead2.normalizedPhone) {
      score += 40;
    }

    // Comparar email (peso medio)
    maxScore += 20;
    if (lead1.normalizedEmail && lead2.normalizedEmail && 
        lead1.normalizedEmail === lead2.normalizedEmail) {
      score += 20;
    }

    // Comparar nombre (peso medio)
    maxScore += 20;
    const nameSimilarity = this.calculateNameSimilarity(lead1.nombre, lead2.nombre);
    score += nameSimilarity * 20;

    // Comparar ciudad (peso bajo)
    maxScore += 10;
    if (lead1.ciudad.toLowerCase() === lead2.ciudad.toLowerCase()) {
      score += 10;
    }

    // Comparar cliente (peso medio)
    maxScore += 10;
    if (lead1.normalizedClient === lead2.normalizedClient) {
      score += 10;
    }

    return maxScore > 0 ? (score / maxScore) * 100 : 0;
  }

  /**
   * Encuentra leads potencialmente duplicados basado en similitud
   */
  findSimilarLeads(
    targetLead: ProcessedSyncLead, 
    candidateLeads: ProcessedSyncLead[], 
    threshold: number = 80
  ): Array<{ lead: ProcessedSyncLead; similarity: number }> {

    const similarLeads = candidateLeads
      .map(candidate => ({
        lead: candidate,
        similarity: this.calculateSimilarityScore(targetLead, candidate)
      }))
      .filter(result => result.similarity >= threshold)
      .sort((a, b) => b.similarity - a.similarity);

    return similarLeads;
  }

  // ========== MÉTODOS PRIVADOS ==========

  private findDuplicateInBatch(
    lead: ProcessedSyncLead, 
    phoneMap: Map<string, ProcessedSyncLead>,
    metaIdMap: Map<string, ProcessedSyncLead>,
    rowNumberMap: Map<string, ProcessedSyncLead>
  ): ProcessedSyncLead | null {

    // Buscar por teléfono normalizado
    const phoneMatch = phoneMap.get(lead.normalizedPhone);
    if (phoneMatch) {
      return phoneMatch;
    }

    // Buscar por metaLeadId
    const metaIdMatch = metaIdMap.get(lead.metaLeadId);
    if (metaIdMatch) {
      return metaIdMatch;
    }

    // Buscar por número de fila de Google Sheets (marca + rowNumber)
    if (lead.googleSheetsRowNumber && lead.marca) {
      const rowKey = `${lead.marca.toUpperCase()}_${lead.googleSheetsRowNumber}`;
      const rowMatch = rowNumberMap.get(rowKey);
      if (rowMatch) {
        return rowMatch;
      }
    }

    return null;
  }

  private normalizePhone(phone: string): string {
    return phone.replace(/[^\d+]/g, '');
  }

  private calculateNameSimilarity(name1: string, name2: string): number {
    if (!name1 || !name2) return 0;

    const n1 = name1.toLowerCase().trim();
    const n2 = name2.toLowerCase().trim();

    if (n1 === n2) return 1;

    // Algoritmo simple de similitud por palabras
    const words1 = n1.split(/\s+/);
    const words2 = n2.split(/\s+/);

    const commonWords = words1.filter(word => words2.includes(word));
    const totalWords = Math.max(words1.length, words2.length);

    return totalWords > 0 ? commonWords.length / totalWords : 0;
  }
}

