                  <tr className="border-b">
                    <th className="text-left p-3 font-medium">MARCA</th>
                    <th className="text-right p-3 font-medium">LEADS META ADS</th>
                    <th className="text-right p-3 font-medium">LEADS REALES</th>
                    <th className="text-right p-3 font-medium">CPL REAL</th>
                    <th className="text-right p-3 font-medium">INVERSIÓN META ADS</th>
                    <th className="text-right p-3 font-medium">MARGEN (2%)</th>
                    <th className="text-right p-3 font-medium">INVERSIÓN TOTAL</th>
                    <th className="text-right p-3 font-medium">FACTURACIÓN</th>
                    <th className="text-right p-3 font-medium">GANANCIA</th>
                    <th className="text-center p-3 font-medium">ROI</th>
                  </tr>
                </thead>
                <tbody>
                  {data.data.map((item, index) => (
                    <tr 
                      key={item.marca} 
                      className="border-b hover:bg-muted/50 transition-colors"
                      data-testid={`row-brand-${index}`}
                    >
                      <td className="p-3">
                        <div className="flex items-center gap-2">
                          <span className="font-medium">{item.marca}</span>
                          <Badge variant="outline" className="text-xs">
                            {item.campanasMetaAds.length} campañas
                          </Badge>
                        </div>
                      </td>
                      <td className="p-3 text-right" data-testid={`text-leads-meta-${index}`}>
                        <div className="text-blue-600 font-medium">
                          {item.leadsMetaAds.toLocaleString()}
                        </div>
                      </td>
                      <td className="p-3 text-right" data-testid={`text-leads-reales-${index}`}>
                        <div className="text-green-600 font-medium">
                          {item.leadsReales.toLocaleString()}
                        </div>
                        {item.diferenciALeads !== 0 && (
                          <div className="text-xs text-muted-foreground">
                            {item.diferenciALeads > 0 ? '+' : ''}{item.diferenciALeads} 
                            ({item.diferencPorcentajeLeads > 0 ? '+' : ''}{item.diferencPorcentajeLeads.toFixed(1)}%)
                          </div>
                        )}
                      </td>
                      <td className="p-3 text-right font-mono" data-testid={`text-cpl-real-${index}`}>
                        <div>{formatCurrency(item.cplReal)}</div>
                        <div className="text-xs text-muted-foreground">
                          Meta: {formatCurrency(item.cplMetaAds)}
                        </div>
                      </td>
                      <td className="p-3 text-right font-mono" data-testid={`text-inversion-meta-${index}`}>
                        {formatCurrency(item.inversionMetaAds)}
                      </td>
                      <td className="p-3 text-right font-mono" data-testid={`text-margen-${index}`}>
                        {formatCurrency(item.impuestosMetaAds)}
                      </td>
                      <td className="p-3 text-right font-mono" data-testid={`text-inversion-total-${index}`}>
                        {formatCurrency(item.inversionTotal)}
                      </td>
                      <td className="p-3 text-right font-mono" data-testid={`text-facturacion-${index}`}>
                        {formatCurrency(item.facturacionBruta)}
                      </td>
                      <td className="p-3 text-right font-mono" data-testid={`text-ganancia-${index}`}>
                        {formatCurrency(item.ganancia)}
                      </td>
                      <td className="p-3 text-center">
                        <div className="flex items-center justify-center gap-2">
                          {getTrendIcon(item.roi)}
                          <Badge variant={getBadgeVariant(item.roi)}>
                            {item.roi.toFixed(1)}%
                          </Badge>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {data.data.length === 0 && (
              <div className="text-center py-8 text-muted-foreground">
                No se encontraron datos para el rango de fechas seleccionado
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Estado de carga */}
      {isLoading && (
        <Card>
          <CardContent className="p-8">
            <div className="flex items-center justify-center space-x-2">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-primary"></div>
              <p>Obteniendo datos de Meta Ads y calculando finanzas...</p>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Estado de error */}
      {error && (
        <Card className="border-destructive">
          <CardContent className="p-6">
            <div className="text-center space-y-2">
              <p className="text-destructive font-medium">Error al obtener análisis financiero</p>
              <p className="text-sm text-muted-foreground">
                {error instanceof Error ? error.message : 'Error desconocido'}
              </p>
              <Button onClick={handleAnalyze} variant="outline" size="sm">
                Reintentar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Información adicional */}
      <Card className="bg-muted/30">
        <CardContent className="p-4">
          <div className="space-y-2">
            <h4 className="font-medium flex items-center gap-2">
              <Calculator className="h-4 w-4" />
              Explicación del Análisis Financiero
            </h4>
            <div className="text-sm text-muted-foreground space-y-1">
              <p><strong>Inversión Meta Ads:</strong> Gasto real reportado por Meta Ads (puro, sin margen)</p>
              <p><strong>Impuestos Meta Ads:</strong> 2% del gasto Meta Ads para costos administrativos</p>
              <p><strong>Inversión Total:</strong> Inversión Meta Ads + Impuestos Meta Ads</p>
              <p><strong>Facturación:</strong> Valores reales de campañas comerciales registradas</p>
              <p><strong>Ganancia:</strong> Facturación - Inversión Total (fórmula simplificada)</p>
              <p><strong>ROI:</strong> (Ganancia / Inversión Total) × 100</p>
              <Separator className="my-2" />
              <p className="text-xs">
                Los datos de inversión provienen directamente de Meta Ads API. 
                Las tasas de conversión son configurables por marca.
              </p>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

query-closed-campaigns.ts.content:
import { db } from './server/db';
import { campanasComerciales, clientes } from './shared/schema';
import { isNotNull, eq, desc } from 'drizzle-orm';
import * as fs from 'fs';
import * as path from 'path';

async function getClosedCampaigns() {
  console.log('📊 Consultando campañas cerradas...\n');

  const closedCampaigns = await db
    .select({
      id: campanasComerciales.id,
      campana: campanasComerciales.numeroCampana,
      marca: campanasComerciales.marca,
      zona: campanasComerciales.zona,
      meta: campanasComerciales.cantidadDatosSolicitados,
      inicio: campanasComerciales.fechaCampana,
      cierre: campanasComerciales.fechaFin,
      cliente: clientes.nombreComercial,
      clienteId: campanasComerciales.clienteId,
    })
    .from(campanasComerciales)
    .leftJoin(clientes, eq(campanasComerciales.clienteId, clientes.id))
    .where(isNotNull(campanasComerciales.fechaFin))
    .orderBy(desc(campanasComerciales.fechaFin))
    .limit(100);

  // Generar el reporte
  let report = '';

  report += '╔═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗\n';
  report += '║                                      REPORTE DE CAMPAÑAS CERRADAS                                                 ║\n';
  report += '║                                     Generado: ' + new Date().toLocaleString('es-AR').padEnd(60) + '║\n';
  report += '╚═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝\n\n';

  report += `Total de campañas cerradas: ${closedCampaigns.length}\n\n`;
  report += '═'.repeat(120) + '\n';
  report +=
    'ID'.padEnd(6) +
    'Cliente'.padEnd(25) +
    'Campaña'.padEnd(10) +
    'Marca'.padEnd(15) +
    'Zona'.padEnd(12) +
    'Meta'.padEnd(8) +
    'Fecha Inicio'.padEnd(20) +
    'Fecha Cierre\n';
  report += '═'.repeat(120) + '\n';

  closedCampaigns.forEach((camp) => {
    const inicio = camp.inicio ? new Date(camp.inicio).toISOString().split('T')[0] : 'N/A';
    const cierre = camp.cierre ? new Date(camp.cierre).toISOString().split('T')[0] : 'N/A';

    report +=
      String(camp.id).padEnd(6) +
      (camp.cliente || 'N/A').substring(0, 24).padEnd(25) +
      String(camp.campana || 'N/A').padEnd(10) +
      (camp.marca || 'N/A').substring(0, 14).padEnd(15) +
      (camp.zona || 'N/A').substring(0, 11).padEnd(12) +
      String(camp.meta || 0).padEnd(8) +
      inicio.padEnd(20) +
      cierre + '\n';
  });

  report += '═'.repeat(120) + '\n\n';

  // Estadísticas por cliente
  const clientStats = closedCampaigns.reduce((acc, camp) => {
    const cliente = camp.cliente || 'N/A';
    if (!acc[cliente]) {
      acc[cliente] = { count: 0, totalLeads: 0 };
    }
    acc[cliente].count++;
    acc[cliente].totalLeads += camp.meta || 0;
    return acc;
  }, {} as Record<string, { count: number; totalLeads: number }>);

  report += '📈 ESTADÍSTICAS POR CLIENTE\n';
  report += '─'.repeat(80) + '\n';
  Object.entries(clientStats)
    .sort((a, b) => b[1].count - a[1].count)
    .forEach(([cliente, stats]) => {
      report +=
        cliente.padEnd(40) +
        `Campañas: ${stats.count}`.padEnd(20) +
        `Leads totales: ${stats.totalLeads}\n`;
    });

  // Estadísticas por marca
  const brandStats = closedCampaigns.reduce((acc, camp) => {
    const marca = camp.marca || 'N/A';
    if (!acc[marca]) {
      acc[marca] = { count: 0, totalLeads: 0 };
    }
    acc[marca].count++;
    acc[marca].totalLeads += camp.meta || 0;
    return acc;
  }, {} as Record<string, { count: number; totalLeads: number }>);

  report += '\n📊 ESTADÍSTICAS POR MARCA\n';
  report += '─'.repeat(80) + '\n';
  Object.entries(brandStats)
    .sort((a, b) => b[1].count - a[1].count)
    .forEach(([marca, stats]) => {
      report +=
        marca.padEnd(40) +
        `Campañas: ${stats.count}`.padEnd(20) +
        `Leads totales: ${stats.totalLeads}\n`;
    });

  // Estadísticas por zona
  const zoneStats = closedCampaigns.reduce((acc, camp) => {
    const zona = camp.zona || 'N/A';
    if (!acc[zona]) {
      acc[zona] = { count: 0, totalLeads: 0 };
    }
    acc[zona].count++;
    acc[zona].totalLeads += camp.meta || 0;
    return acc;
  }, {} as Record<string, { count: number; totalLeads: number }>);

  report += '\n🗺️  ESTADÍSTICAS POR ZONA\n';
  report += '─'.repeat(80) + '\n';
  Object.entries(zoneStats)
    .sort((a, b) => b[1].count - a[1].count)
    .forEach(([zona, stats]) => {
      report +=
        zona.padEnd(40) +
        `Campañas: ${stats.count}`.padEnd(20) +
        `Leads totales: ${stats.totalLeads}\n`;
    });

  // Resumen general
  const totalLeads = closedCampaigns.reduce((sum, camp) => sum + (camp.meta || 0), 0);
  report += '\n' + '═'.repeat(120) + '\n';
  report += '📊 RESUMEN GENERAL\n';
  report += '─'.repeat(80) + '\n';
  report += `Total de campañas cerradas: ${closedCampaigns.length}\n`;
  report += `Total de leads procesados: ${totalLeads}\n`;
  report += `Promedio de leads por campaña: ${Math.round(totalLeads / closedCampaigns.length)}\n`;
  report += `Clientes únicos: ${Object.keys(clientStats).length}\n`;
  report += `Marcas únicas: ${Object.keys(brandStats).length}\n`;
  report += `Zonas únicas: ${Object.keys(zoneStats).length}\n`;
  report += '═'.repeat(120) + '\n';

  // Guardar el reporte en archivo
  const timestamp = new Date().toISOString().replace(/:/g, '-').split('.')[0];
  const filename = `reporte-campanas-cerradas-${timestamp}.txt`;
  const filepath = path.join(process.cwd(), filename);

  fs.writeFileSync(filepath, report, 'utf-8');

  console.log(report);
  console.log(`\n✅ Reporte guardado en: ${filepath}`);

  process.exit(0);
}

getClosedCampaigns().catch((error) => {
  console.error('❌ Error:', error);
  process.exit(1);
});

client/src/pages/lead-details.tsx.content:
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useParams, Link } from "wouter";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { ArrowLeft, Phone, Mail, MapPin, DollarSign, Calendar, MessageSquare, Save } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Navigation } from "@/components/navigation";

interface Lead {
  id: number;
  metaLeadId: string | null;
  firstName: string | null;
  lastName: string | null;
  email: string | null;
  phone: string | null;
  age: number | null;
  city: string | null;
  interest: string | null;
  budget: string | null;
  adName: string | null;
  adsetName: string | null;
  campaignName: string | null;
  status: string;
  source: string;
  cost: string | null;
  leadDate: string | null;
  createdAt: string;
  updatedAt: string;
}

interface LeadNote {
  id: number;
  leadId: number;
  userId: number;
  note: string;
  type: string;
  createdAt: string;
}

export default function LeadDetails() {
  const params = useParams();
  const leadId = params.id;
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [status, setStatus] = useState("");
  const [newNote, setNewNote] = useState("");
  const [noteType, setNoteType] = useState("general");

  // Fetch lead details
  const { data: lead, isLoading: leadLoading, error } = useQuery<Lead>({
    queryKey: ['/api/leads', leadId],
    queryFn: () => fetch(`/api/leads/${leadId}`).then(res => {
      if (!res.ok) throw new Error('Lead not found');
      return res.json();
    }),
    enabled: !!leadId
  });

  // Fetch lead notes
  const { data: notes = [] } = useQuery<LeadNote[]>({
    queryKey: ['/api/leads', leadId, 'notes'],
    queryFn: () => fetch(`/api/leads/${leadId}/notes`).then(res => res.json()),
    enabled: !!leadId
  });

  // Set initial status when lead loads
  React.useEffect(() => {
    if (lead && !status) {
      setStatus(lead.status);
    }
  }, [lead, status]);

  // Update lead status mutation
  const updateLeadMutation = useMutation({
    mutationFn: async (updates: { status: string }) => {
      const response = await fetch(`/api/leads/${leadId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(updates),
      });
      if (!response.ok) throw new Error('Failed to update lead');
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Lead actualizado",
        description: "El estado del lead se ha actualizado correctamente.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/leads', leadId] });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "No se pudo actualizar el lead.",
        variant: "destructive",
      });
    }
  });

  // Add note mutation
  const addNoteMutation = useMutation({
    mutationFn: async (noteData: { note: string; type: string; userId: number }) => {
      const response = await fetch(`/api/leads/${leadId}/notes`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(noteData),
      });
      if (!response.ok) throw new Error('Failed to add note');
      return response.json();
    },
    onSuccess: () => {
      setNewNote("");
      toast({
        title: "Nota agregada",
        description: "La nota se ha guardado correctamente.",
      });
      queryClient.invalidateQueries({ queryKey: ['/api/leads', leadId, 'notes'] });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "No se pudo agregar la nota.",
        variant: "destructive",
      });
    }
  });

  const handleUpdateStatus = () => {
    if (status && status !== lead?.status) {
      updateLeadMutation.mutate({ status });
    }
  };

  const handleAddNote = (e: React.FormEvent) => {
    e.preventDefault();
    if (newNote.trim()) {
      addNoteMutation.mutate({
        note: newNote.trim(),
        type: noteType,
        userId: 1 // Simple user ID for demo
      });
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'new': return 'bg-blue-100 text-blue-800';
      case 'contacted': return 'bg-yellow-100 text-yellow-800';
      case 'qualified': return 'bg-purple-100 text-purple-800';
      case 'converted': return 'bg-green-100 text-green-800';
      case 'rejected': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getNoteTypeIcon = (type: string) => {
    switch (type) {
      case 'call': return <Phone className="h-4 w-4" />;
      case 'email': return <Mail className="h-4 w-4" />;
      case 'meeting': return <Calendar className="h-4 w-4" />;
      default: return <MessageSquare className="h-4 w-4" />;
    }
  };

  if (leadLoading) {
    return (
      <div className="min-h-screen bg-gray-50 p-6">
        <Navigation />
        <div className="max-w-4xl mx-auto">
          <div className="text-center py-12">Cargando lead...</div>
        </div>
      </div>
    );
  }

  if (error || !lead) {
    return (
      <div className="min-h-screen bg-gray-50 p-6">
        <Navigation />
        <div className="max-w-4xl mx-auto">
          <Alert variant="destructive">
            <AlertDescription>
              No se pudo cargar la información del lead. Puede que no exista o haya ocurrido un error.
            </AlertDescription>
          </Alert>
          <div className="mt-4">
            <Link href="/">
              <Button variant="outline">
                <ArrowLeft className="h-4 w-4 mr-2" />
                Volver al Dashboard
              </Button>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <Navigation />
      <div className="max-w-4xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <Link href="/">
              <Button variant="outline" size="sm">
                <ArrowLeft className="h-4 w-4 mr-2" />
                Volver
              </Button>
            </Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">
                {lead.firstName} {lead.lastName}
              </h1>
              <p className="text-gray-600">Lead ID: {lead.id}</p>
            </div>
          </div>
          <Badge className={getStatusColor(lead.status)}>
            {lead.status}
          </Badge>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Lead Information */}
          <div className="lg:col-span-2 space-y-6">
            {/* Contact Info */}
            <Card>
              <CardHeader>
                <CardTitle>Información de Contacto</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="flex items-center space-x-2">
                    <Mail className="h-4 w-4 text-gray-500" />
                    <span>{lead.email || "No disponible"}</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <Phone className="h-4 w-4 text-gray-500" />
                    <span>{lead.phone || "No disponible"}</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <MapPin className="h-4 w-4 text-gray-500" />
                    <span>{lead.city || "No disponible"}</span>
                  </div>
                  <div className="flex items-center space-x-2">
                    <Calendar className="h-4 w-4 text-gray-500" />
                    <span>
                      {lead.age ? `${lead.age} años` : "Edad no disponible"}
                    </span>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Lead Details */}
            <Card>
              <CardHeader>
                <CardTitle>Detalles del Lead</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <Label className="font-medium">Interés</Label>
                  <p>{lead.interest || "No especificado"}</p>
                </div>
                <div>
                  <Label className="font-medium">Presupuesto</Label>
                  <p>{lead.budget || "No especificado"}</p>
                </div>
                <div>
                  <Label className="font-medium">Campaña</Label>
                  <p>{lead.campaignName || "No disponible"}</p>
                </div>
                <div>
                  <Label className="font-medium">Anuncio</Label>
                  <p>{lead.adName || "No disponible"}</p>
                </div>
                <div>
                  <Label className="font-medium">Conjunto de Anuncios</Label>
                  <p>{lead.adsetName || "No disponible"}</p>
                </div>
              </CardContent>
            </Card>

            {/* Meta Information */}
            <Card>
              <CardHeader>
                <CardTitle>Información de Meta</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <Label className="font-medium">ID Meta Lead</Label>
                    <p className="text-sm text-gray-600">{lead.metaLeadId || "No disponible"}</p>
                  </div>
                  <div>
                    <Label className="font-medium">Fuente</Label>
                    <p>{lead.source}</p>
                  </div>
                  <div className="flex items-center space-x-2">
                    <DollarSign className="h-4 w-4 text-gray-500" />
                    <div>
                      <Label className="font-medium">Costo</Label>
                      <p>{lead.cost ? `$${lead.cost}` : "No disponible"}</p>
                    </div>
                  </div>
                  <div>
                    <Label className="font-medium">Fecha del Lead</Label>
                    <p>
                      {lead.leadDate ? 
                        new Date(lead.leadDate).toLocaleDateString('es-ES') : 
                        new Date(lead.createdAt).toLocaleDateString('es-ES')
                      }
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Update Status */}
            <Card>
              <CardHeader>
                <CardTitle>Actualizar Estado</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <Label htmlFor="status">Estado</Label>
                  <Select value={status || "new"} onValueChange={setStatus}>
                    <SelectTrigger>
                      <SelectValue placeholder="Seleccionar estado" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="new">Nuevo</SelectItem>
                      <SelectItem value="contacted">Contactado</SelectItem>
                      <SelectItem value="qualified">Calificado</SelectItem>
                      <SelectItem value="converted">Convertido</SelectItem>
                      <SelectItem value="rejected">Rechazado</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <Button 
                  onClick={handleUpdateStatus}
                  disabled={updateLeadMutation.isPending || status === lead.status}
                  className="w-full"
                >
                  <Save className="h-4 w-4 mr-2" />
                  {updateLeadMutation.isPending ? "Actualizando..." : "Actualizar Estado"}
                </Button>
              </CardContent>
            </Card>

            {/* Add Note */}
            <Card>
              <CardHeader>
                <CardTitle>Agregar Nota</CardTitle>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleAddNote} className="space-y-4">
                  <div>
                    <Label htmlFor="noteType">Tipo de Nota</Label>
                    <Select value={noteType} onValueChange={setNoteType}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="general">General</SelectItem>
                        <SelectItem value="call">Llamada</SelectItem>
                        <SelectItem value="email">Email</SelectItem>
                        <SelectItem value="meeting">Reunión</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div>
                    <Label htmlFor="note">Nota</Label>
                    <Textarea
                      id="note"
                      value={newNote}
                      onChange={(e) => setNewNote(e.target.value)}
                      placeholder="Escribe una nota sobre este lead..."
                      rows={3}
                    />
                  </div>

                  <Button 
                    type="submit"
                    disabled={addNoteMutation.isPending || !newNote.trim()}
                    className="w-full"
                  >
                    {addNoteMutation.isPending ? "Guardando..." : "Agregar Nota"}
                  </Button>
                </form>
              </CardContent>
            </Card>

            {/* Notes History */}
            <Card>
              <CardHeader>
                <CardTitle>Historial de Notas ({notes.length})</CardTitle>
              </CardHeader>
              <CardContent>
                {notes.length === 0 ? (
                  <p className="text-gray-500 text-sm">No hay notas para este lead</p>
                ) : (
                  <div className="space-y-3 max-h-64 overflow-y-auto">
                    {notes.map(note => (
                      <div key={note.id} className="border-l-2 border-gray-200 pl-3">
                        <div className="flex items-center space-x-2 mb-1">
                          {getNoteTypeIcon(note.type)}
                          <span className="text-sm font-medium capitalize">{note.type}</span>
                          <span className="text-xs text-gray-500">
                            {new Date(note.createdAt).toLocaleDateString('es-ES')}
                          </span>
                        </div>
                        <p className="text-sm text-gray-700">{note.note}</p>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </div>
    </div>
  );
}

