import { Request, Response } from 'express';
import { FinishedCampaignFactory } from '../../infrastructure/factories/FinishedCampaignFactory';
import { FinishedCampaignFilters } from '../../domain/entities/FinishedCampaign';

/**
 * Controlador REST para campañas finalizadas
 * Maneja las peticiones HTTP y delega la lógica a los casos de uso
 */
export class FinishedCampaignController {
  /**
   * GET /api/finished-campaigns
   * Obtiene todas las campañas finalizadas con filtros opcionales
   * NUEVO: Enriquece los datos con métricas calculadas desde op_leads_rep
   */
  async getFinishedCampaigns(req: Request, res: Response): Promise<void> {
    try {
      console.log('📥 [FinishedCampaignController] GET /api/finished-campaigns');
      console.log('📋 Query params:', req.query);

      // Construir filtros desde query params
      const filters: FinishedCampaignFilters = {};

      if (req.query.zona) filters.zona = req.query.zona as string;
      if (req.query.marca) filters.marca = req.query.marca as string;
      if (req.query.cliente) filters.cliente = req.query.cliente as string;
      if (req.query.clienteNombre) filters.clienteNombre = req.query.clienteNombre as string;
      if (req.query.fechaInicio) filters.fechaInicio = req.query.fechaInicio as string;
      if (req.query.fechaFin) filters.fechaFin = req.query.fechaFin as string;
      if (req.query.fechaCierreInicio) filters.fechaCierreInicio = req.query.fechaCierreInicio as string;
      if (req.query.fechaCierreFin) filters.fechaCierreFin = req.query.fechaCierreFin as string;
      if (req.query.showDuplicatesOnly) filters.showDuplicatesOnly = req.query.showDuplicatesOnly === 'true';
      if (req.query.sortBy) filters.sortBy = req.query.sortBy as any;
      if (req.query.sortOrder) filters.sortOrder = req.query.sortOrder as any;

      const includeStats = req.query.includeStats === 'true';

      // Ejecutar caso de uso
      const useCase = FinishedCampaignFactory.createGetFinishedCampaignsUseCase();
      const result = await useCase.execute(filters, includeStats);

      // 🔥 NUEVO: Enriquecer campañas con datos reales desde op_leads_rep
      console.log('🔄 [FinishedCampaignController] Enriqueciendo campañas con datos de leads...');
      const enrichmentService = FinishedCampaignFactory.getEnrichmentService();

      // Obtener todos los clientes necesarios
      const { storage } = await import('../../../storage');
      const clienteIds = [...new Set(result.campaigns.map(c => c.clienteId))];
      const clientesMap = new Map();

      for (const clienteId of clienteIds) {
        const cliente = await storage.getCliente(clienteId);
        if (cliente) {
          clientesMap.set(clienteId, cliente);
        }
      }

      // Obtener todas las campañas comerciales para contexto de cálculo
      const campanasComerciales = await storage.getAllCampanasComerciales();

      // Enriquecer todas las campañas en paralelo
      const enrichedCampaigns = await enrichmentService.enrichCampaigns(
        result.campaigns,
        clientesMap,
        campanasComerciales
      );

      console.log(`✅ [FinishedCampaignController] ${enrichedCampaigns.length} campañas enriquecidas`);

      res.json({
        success: true,
        data: enrichedCampaigns,
        count: enrichedCampaigns.length,
        stats: result.stats,
        timestamp: new Date().toISOString()
      });
    } catch (error: any) {
      console.error('❌ [FinishedCampaignController] Error en getFinishedCampaigns:', error);
      res.status(500).json({
        success: false,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }

  /**
   * GET /api/finished-campaigns/stats
   * Obtiene estadísticas agregadas de campañas finalizadas
   */
  async getStatistics(req: Request, res: Response): Promise<void> {
    try {
      console.log('📊 [FinishedCampaignController] GET /api/finished-campaigns/stats');

      // Construir filtros desde query params
      const filters: FinishedCampaignFilters = {};
      if (req.query.zona) filters.zona = req.query.zona as string;
      if (req.query.marca) filters.marca = req.query.marca as string;
      if (req.query.cliente) filters.cliente = req.query.cliente as string;

      // Ejecutar caso de uso
      const useCase = FinishedCampaignFactory.createGetFinishedCampaignStatsUseCase();
      const stats = await useCase.execute(filters);

      res.json({
        success: true,
        data: stats,
        timestamp: new Date().toISOString()
      });
    } catch (error: any) {
      console.error('❌ [FinishedCampaignController] Error en getStatistics:', error);
      res.status(500).json({
        success: false,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }

  /**
   * GET /api/finished-campaigns/filters/options
   * Obtiene opciones disponibles para filtros
   */
  async getFilterOptions(req: Request, res: Response): Promise<void> {
    try {
      console.log('🔧 [FinishedCampaignController] GET /api/finished-campaigns/filters/options');

      const repository = FinishedCampaignFactory.getRepository();

      const [clientes, marcas, zonas] = await Promise.all([
        repository.getClientsWithFinishedCampaigns(),
        repository.getBrandsWithFinishedCampaigns(),
        repository.getZonesWithFinishedCampaigns()
      ]);

      res.json({
        success: true,
        data: {
          clientes,
          marcas,
          zonas
        },
        timestamp: new Date().toISOString()
      });
    } catch (error: any) {
      console.error('❌ [FinishedCampaignController] Error en getFilterOptions:', error);
      res.status(500).json({
        success: false,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }

  /**
   * GET /api/finished-campaigns/:id
   * Obtiene una campaña finalizada específica
   */
  async getCampaignById(req: Request, res: Response): Promise<void> {
    try {
      const id = parseInt(req.params.id);
      console.log(`🔍 [FinishedCampaignController] GET /api/finished-campaigns/${id}`);

      if (isNaN(id)) {
        res.status(400).json({
          success: false,
          error: 'ID de campaña inválido',
          timestamp: new Date().toISOString()
        });
        return;
      }

      // Ejecutar caso de uso
      const useCase = FinishedCampaignFactory.createGetFinishedCampaignByIdUseCase();
      const campaign = await useCase.execute(id);

      if (!campaign) {
        res.status(404).json({
          success: false,
          error: 'Campaña no encontrada',
          timestamp: new Date().toISOString()
        });
        return;
      }

      res.json({
        success: true,
        data: campaign,
        timestamp: new Date().toISOString()
      });
    } catch (error: any) {
      console.error('❌ [FinishedCampaignController] Error en getCampaignById:', error);
      res.status(500).json({
        success: false,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }

  /**
   * GET /api/finished-campaigns/:id/can-reopen
   * Verifica si una campaña puede ser reabierta
   */
  async canReopenCampaign(req: Request, res: Response): Promise<void> {
    try {
      const id = parseInt(req.params.id);
      console.log(`🔍 [FinishedCampaignController] GET /api/finished-campaigns/${id}/can-reopen`);

      if (isNaN(id)) {
        res.status(400).json({
          success: false,
          error: 'ID de campaña inválido',
          timestamp: new Date().toISOString()
        });
        return;
      }

      // Validar si se puede reabrir
      const service = FinishedCampaignFactory.getService();
      const validation = await service.canReopen(id);

      res.json({
        success: true,
        data: {
          canReopen: validation.canReopen,
          reason: validation.reason || 'La campaña puede ser reabierta'
        },
        timestamp: new Date().toISOString()
      });
    } catch (error: any) {
      console.error('❌ [FinishedCampaignController] Error en canReopenCampaign:', error);
      res.status(500).json({
        success: false,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }

  /**
   * POST /api/finished-campaigns/:id/reopen
   * Reabre una campaña finalizada
   */
  async reopenCampaign(req: Request, res: Response): Promise<void> {
    try {
      const id = parseInt(req.params.id);
      console.log(`🔄 [FinishedCampaignController] POST /api/finished-campaigns/${id}/reopen`);

      if (isNaN(id)) {
        res.status(400).json({
          success: false,
          error: 'ID de campaña inválido',
          timestamp: new Date().toISOString()
        });
        return;
      }

      // Validar si se puede reabrir
      const service = FinishedCampaignFactory.getService();
      const validation = await service.canReopen(id);

      if (!validation.canReopen) {
        res.status(400).json({
          success: false,
          error: validation.reason,
          timestamp: new Date().toISOString()
        });
        return;
      }

      // Ejecutar caso de uso
      const useCase = FinishedCampaignFactory.createReopenFinishedCampaignUseCase();
      const result = await useCase.execute(id);

      if (!result.success) {
        res.status(500).json({
          success: false,
          error: result.message,
          errors: result.errors,
          timestamp: new Date().toISOString()
        });
        return;
      }

      res.json({
        success: true,
        message: result.message,
        campaignId: id,
        timestamp: new Date().toISOString()
      });
    } catch (error: any) {
      console.error('❌ [FinishedCampaignController] Error en reopenCampaign:', error);
      res.status(500).json({
        success: false,
        error: error.message,
        timestamp: new Date().toISOString()
      });
    }
  }
}

shared/utils/percentage-utils.ts.content:
/**
 * Utilidades centralizadas para cálculos de porcentajes
 * Factorización de la fórmula % Datos Enviados
 */

export interface PercentageCalculationResult {
  percentage: number;
  isComplete: boolean;
  isOverTarget: boolean;
  decimal: number;
}

/**
 * Calcula el porcentaje de datos enviados de forma consistente
 * @param enviados - Cantidad de datos enviados
 * @param solicitados - Cantidad de datos solicitados
 * @param options - Opciones de cálculo
 * @returns Resultado del cálculo con metadata adicional
 */
export function calculateDatosEnviadosPercentage(
  enviados: number,
  solicitados: number,
  options: {
    roundToInteger?: boolean;
    capAt100?: boolean;
  } = {}
): PercentageCalculationResult {
  const { roundToInteger = true, capAt100 = false } = options;

  // Validación de inputs
  if (solicitados <= 0) {
    return {
      percentage: 0,
      isComplete: false,
      isOverTarget: false,
      decimal: 0
    };
  }

  // Cálculo base como decimal
  const decimal = enviados / solicitados;

  // Convertir a porcentaje
  let percentage = decimal * 100;

  // Aplicar redondeo si se solicita
  if (roundToInteger) {
    percentage = Math.round(percentage);
  }

  // Aplicar límite si se solicita
  if (capAt100) {
    percentage = Math.min(100, percentage);
  }

  return {
    percentage,
    isComplete: percentage >= 100,
    isOverTarget: percentage > 100,
    decimal: capAt100 ? Math.min(1, decimal) : decimal
  };
}

/**
 * Calcula faltantes a enviar
 * @param enviados - Cantidad enviada
 * @param solicitados - Cantidad solicitada
 * @returns Cantidad faltante (nunca negativa)
 */
export function calculateFaltantesAEnviar(enviados: number, solicitados: number): number {
  return Math.max(0, solicitados - enviados);
}

/**
 * Calcula el porcentaje de desvío: Pedidos/día ÷ Entregados/día
 * @param pedidosPorDia - Pedidos por día
 * @param entregadosPorDia - Entregados por día
 * @param options - Opciones de cálculo
 * @returns Resultado del cálculo de desvío
 */
export function calculatePorcentajeDesvio(
  pedidosPorDia: number,
  entregadosPorDia: number,
  options: {
    roundToInteger?: boolean;
    returnAsPercentage?: boolean;
  } = {}
): number {
  const { roundToInteger = true, returnAsPercentage = false } = options;

  // Validación de inputs
  if (entregadosPorDia <= 0) {
    return 0;
  }

  // Cálculo: Pedidos/día ÷ Entregados/día
  let desvio = pedidosPorDia / entregadosPorDia;

  // Convertir a porcentaje si se solicita
  if (returnAsPercentage) {
    desvio = desvio * 100;
  }

  // Aplicar redondeo si se solicita
  if (roundToInteger) {
    desvio = Math.round(desvio);
  }

  return desvio;
}

/**
 * Formatea el porcentaje para display
 * @param percentage - Porcentaje a formatear
 * @param decimals - Cantidad de decimales
 * @returns String formateado con símbolo %
 */
export function formatPercentage(percentage: number, decimals: number = 1): string {
  return `${percentage.toFixed(decimals)}%`;
}

/**
 * Versiones legacy para compatibilidad - DEPRECADAS
 * @deprecated Usar calculateDatosEnviadosPercentage en su lugar
 */
export const legacyCalculations = {
  /**
   * @deprecated - Inconsistente, falta * 100
   */
  routesV1: (enviados: number, solicitados: number) =>
    solicitados > 0 ? Math.round(enviados / solicitados) : 0,

  /**
   * @deprecated - Retorna decimal en lugar de porcentaje
   */
  routesV2: (enviados: number, solicitados: number) =>
    Math.min(1, enviados / solicitados),

  /**
   * Versión correcta de quick-optimized
   */
  quickOptimized: (enviados: number, solicitados: number) =>
    solicitados > 0 ? Math.round((enviados / solicitados) * 100) : 0
};

client/src/components/sent-leads-modal.t.content:
import { useQuery } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Loader2, Mail, Phone, MapPin, Calendar, User, Tag } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useMemo, useState } from "react";

interface SentLead {
  id: number;
  metaLeadId: string;
  nombre: string;
  telefono: string;
  email: string | null;
  ciudad: string | null;
  modelo: string | null;
  marca: string;
  campaign: string;
  origen: string | null;
  localizacion: string | null;
  cliente: string | null;
  fechaCreacion: string;
  sentAt: string;
}

interface SentLeadsResponse {
  campaignId: number;
  campaignName: string | null;
  clientName: string | null;
  marca: string | null;
  marca2: string | null;
  marca3: string | null;
  marca4: string | null;
  marca5: string | null;
  zona: string | null;
  totalSent: number;
  leads: SentLead[];
}

interface CampaignData {
  campaignId?: number;
  clienteNombre?: string;
  numeroCampana?: number;
  marca?: string;
  zona?: string;
}

interface SentLeadsModalProps {
  isOpen: boolean;
  onClose: () => void;
  campaignData: CampaignData | null;
}

export function SentLeadsModal({ isOpen, onClose, campaignData }: SentLeadsModalProps) {
  const { data, isLoading, error } = useQuery<SentLeadsResponse>({
    queryKey: [`/api/leads/sent-by-campaign/${campaignData?.campaignId}`],
    enabled: isOpen && !!campaignData?.campaignId,
    staleTime: 0,
  });

  const [activeTab, setActiveTab] = useState<string>("all");

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('es-AR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  // Detectar si es multimarca y obtener lista de marcas
  const campaignBrands = useMemo(() => {
    if (!data) return [];
    const brands: string[] = [];
    if (data.marca) brands.push(data.marca);
    if (data.marca2) brands.push(data.marca2);
    if (data.marca3) brands.push(data.marca3);
    if (data.marca4) brands.push(data.marca4);
    if (data.marca5) brands.push(data.marca5);
    return brands;
  }, [data]);

  const isMultiBrand = campaignBrands.length > 1;

  // Agrupar leads por marca (case-insensitive para coincidir con campaignBrands)
  const leadsByBrand = useMemo(() => {
    if (!data || !data.leads) return {};

    const grouped: Record<string, SentLead[]> = {};

    data.leads.forEach(lead => {
      const leadBrand = lead.marca || 'Sin marca';

      // Buscar la marca correspondiente en campaignBrands (case-insensitive)
      const matchingBrand = campaignBrands.find(
        brand => brand.toLowerCase() === leadBrand.toLowerCase()
      );

      // Usar la marca de la campaña (capitalizada correctamente) como key
      const brandKey = matchingBrand || leadBrand;

      if (!grouped[brandKey]) {
        grouped[brandKey] = [];
      }
      grouped[brandKey].push(lead);
    });

    return grouped;
  }, [data, campaignBrands]);

  // Componente para renderizar lista de leads
  const renderLeadsList = (leads: SentLead[]) => (
    <div className="grid gap-3">
      {leads.map((lead, index) => (
        <div
          key={lead.id}
          className="bg-white border border-slate-200 rounded-lg p-4 hover:shadow-md transition-shadow"
        >
          <div className="flex items-start justify-between mb-3">
            <div className="flex items-center gap-2">
              <span className="text-xs font-medium text-slate-500 bg-slate-100 px-2 py-1 rounded">
                #{index + 1}
              </span>
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <User className="h-4 w-4 text-slate-500" />
                {lead.nombre}
              </h3>
            </div>
            <Badge variant="outline" className="text-xs">
              {lead.marca}
            </Badge>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 text-sm">
            {lead.telefono && (
              <div className="flex items-center gap-2 text-slate-600">
                <Phone className="h-4 w-4 text-blue-500" />
                <span>{lead.telefono}</span>
              </div>
            )}

            {lead.email && (
              <div className="flex items-center gap-2 text-slate-600">
                <Mail className="h-4 w-4 text-purple-500" />
                <span className="truncate">{lead.email}</span>
              </div>
            )}

            {lead.ciudad && (
              <div className="flex items-center gap-2 text-slate-600">
                <MapPin className="h-4 w-4 text-red-500" />
                <span>{lead.ciudad}</span>
              </div>
            )}

            {lead.modelo && (
              <div className="flex items-center gap-2 text-slate-600">
                <Tag className="h-4 w-4 text-orange-500" />
                <span>{lead.modelo}</span>
              </div>
            )}

            <div className="flex items-center gap-2 text-slate-600">
              <Calendar className="h-4 w-4 text-green-500" />
              <span className="text-xs">Creado: {formatDate(lead.fechaCreacion)}</span>
            </div>

            <div className="flex items-center gap-2 text-slate-600">
              <Calendar className="h-4 w-4 text-blue-500" />
              <span className="text-xs">Enviado: {formatDate(lead.sentAt)}</span>
            </div>
          </div>

          {(lead.origen || lead.localizacion || lead.campaign) && (
            <div className="mt-3 pt-3 border-t border-slate-100 flex flex-wrap gap-2">
              {lead.origen && (
                <Badge variant="secondary" className="text-xs">
                  Origen: {lead.origen}
                </Badge>
              )}
              {lead.localizacion && (
                <Badge variant="secondary" className="text-xs">
                  Loc: {lead.localizacion}
                </Badge>
              )}
              {lead.campaign && (
                <Badge variant="outline" className="text-xs">
                  {lead.campaign}
                </Badge>
              )}
            </div>
          )}
        </div>
      ))}
    </div>
  );

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-5xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader className="pb-4 border-b">
          <DialogTitle className="text-2xl font-bold text-slate-800">
            Leads Enviados
          </DialogTitle>
          {campaignData && data && (
            <p className="text-sm text-slate-600 mt-2">
              {campaignData.clienteNombre} - Campaña #{campaignData.numeroCampana} - {isMultiBrand ? 'Multimarca' : `Marca: ${data.marca}`} - {data.totalSent} leads enviados
            </p>
          )}
        </DialogHeader>

        <div className="flex-1 overflow-y-auto py-4">
          {isLoading && (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="h-8 w-8 animate-spin text-blue-600" />
              <span className="ml-3 text-slate-600">Cargando leads...</span>
            </div>
          )}

          {error && (
            <div className="text-center py-12">
              <p className="text-red-600">Error al cargar los leads</p>
              <p className="text-sm text-slate-500 mt-2">
                {error instanceof Error ? error.message : 'Error desconocido'}
              </p>
            </div>
          )}

          {data && data.leads.length === 0 && (
            <div className="text-center py-12">
              <p className="text-slate-500">No hay leads enviados para esta campaña</p>
            </div>
          )}

          {data && data.leads.length > 0 && (
            <>
              {isMultiBrand ? (
                <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
                  <TabsList className="grid w-full mb-4" style={{ gridTemplateColumns: `repeat(${campaignBrands.length + 1}, minmax(0, 1fr))` }}>
                    <TabsTrigger value="all" className="text-sm">
                      Todos ({data.leads.length})
                    </TabsTrigger>
                    {campaignBrands.map(brand => (
                      <TabsTrigger key={brand} value={brand} className="text-sm">
                        {brand} ({leadsByBrand[brand]?.length || 0})
                      </TabsTrigger>
                    ))}
                  </TabsList>

                  <TabsContent value="all" className="mt-0">
                    {renderLeadsList(data.leads)}
                  </TabsContent>

                  {campaignBrands.map(brand => (
                    <TabsContent key={brand} value={brand} className="mt-0">
                      {leadsByBrand[brand] && leadsByBrand[brand].length > 0 ? (
                        renderLeadsList(leadsByBrand[brand])
                      ) : (
                        <div className="text-center py-12">
                          <p className="text-slate-500">No hay leads de {brand}</p>
                        </div>
                      )}
                    </TabsContent>
                  ))}
                </Tabs>
              ) : (
                renderLeadsList(data.leads)
              )}
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

