### Con net/http

```go
package main

import (
    "bytes"
    "encoding/json"
    "fmt"
    "io/ioutil"
    "net/http"
)

type Lead struct {
    Nombre      string `json:"nombre"`
    Telefono    string `json:"telefono"`
    Auto        string `json:"auto,omitempty"`
    Localidad   string `json:"localidad,omitempty"`
    Comentarios string `json:"comentarios,omitempty"`
}

type WebhookResponse struct {
    Success bool        `json:"success"`
    LeadID  int         `json:"leadId"`
    Message string      `json:"message"`
    Data    interface{} `json:"data"`
}

func crearLead(lead Lead) (*WebhookResponse, error) {
    url := "http://localhost:5000/api/webhook/lead-webhook"

    jsonData, err := json.Marshal(lead)
    if err != nil {
        return nil, err
    }

    resp, err := http.Post(url, "application/json", bytes.NewBuffer(jsonData))
    if err != nil {
        return nil, err
    }
    defer resp.Body.Close()

    body, err := ioutil.ReadAll(resp.Body)
    if err != nil {
        return nil, err
    }

    var result WebhookResponse
    err = json.Unmarshal(body, &result)
    if err != nil {
        return nil, err
    }

    return &result, nil
}

func main() {
    lead := Lead{
        Nombre:    "Gabriel Torres",
        Telefono:  "1122334455",
        Auto:      "Honda Civic",
        Localidad: "Tucumán",
    }

    result, err := crearLead(lead)
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    if result.Success {
        fmt.Printf("Lead creado: %d\n", result.LeadID)
    } else {
        fmt.Printf("Error: %s\n", result.Message)
    }
}
