            };
          }

          marcasFinanzas[marcaEncontrada].importeGastado += campaign.spend;
          marcasFinanzas[marcaEncontrada].leadsMetaAds += campaign.results;
          marcasFinanzas[marcaEncontrada].campanas.push(campaign.campaignName);
        }
