import { PendingCampaign, PendingCampaignFilters, PendingCampaignStats } from '../entities/PendingCampaign';

/**
 * Contrato para el repositorio de campañas pendientes
 * Define las operaciones de acceso a datos
 */
export interface IPendingCampaignRepository {
  /**
   * Obtiene todas las campañas pendientes (fechaFin = null)
   * @param filters - Filtros opcionales para la consulta
   * @returns Array de campañas pendientes
   */
  findAllPending(filters?: PendingCampaignFilters): Promise<PendingCampaign[]>;

  /**
   * Obtiene una campaña pendiente por ID
   * @param id - ID de la campaña
   * @returns Campaña pendiente o null si no existe
   */
  findById(id: number): Promise<PendingCampaign | null>;

  /**
   * Obtiene campañas pendientes por cliente
   * @param clientName - Nombre del cliente
   * @returns Array de campañas pendientes del cliente
   */
  findByClient(clientName: string): Promise<PendingCampaign[]>;

  /**
   * Obtiene campañas pendientes por marca
   * @param brandName - Nombre de la marca
   * @returns Array de campañas pendientes de la marca
   */
  findByBrand(brandName: string): Promise<PendingCampaign[]>;

  /**
   * Obtiene campañas pendientes por zona
   * @param zone - Zona geográfica
   * @returns Array de campañas pendientes de la zona
   */
  findByZone(zone: string): Promise<PendingCampaign[]>;

  /**
   * Actualiza una campaña pendiente
   * @param id - ID de la campaña
   * @param data - Datos parciales a actualizar
   */
  update(id: number, data: Partial<PendingCampaign>): Promise<void>;

  /**
   * Obtiene estadísticas agregadas de campañas pendientes
   * @param filters - Filtros opcionales
   * @returns Estadísticas calculadas
   */
  getStatistics(filters?: PendingCampaignFilters): Promise<PendingCampaignStats>;

  /**
   * Cuenta el total de campañas pendientes
   * @param filters - Filtros opcionales
   * @returns Número total de campañas pendientes
   */
  count(filters?: PendingCampaignFilters): Promise<number>;

  /**
   * Verifica si existe una campaña pendiente
   * @param id - ID de la campaña
   * @returns true si existe, false en caso contrario
   */
  exists(id: number): Promise<boolean>;

  /**
   * Obtiene clientes con campañas pendientes
   * @returns Array de nombres de clientes únicos
   */
  getClientsWithPendingCampaigns(): Promise<string[]>;

  /**
   * Obtiene marcas con campañas pendientes
   * @returns Array de nombres de marcas únicos
   */
  getBrandsWithPendingCampaigns(): Promise<string[]>;

  /**
   * Obtiene zonas con campañas pendientes
   * @returns Array de zonas únicas
   */
  getZonesWithPendingCampaigns(): Promise<string[]>;
}

server/webhook/domain/entities/WebhookLe.content:
/**
 * Entidad de dominio para leads recibidos via webhook
 */
export class WebhookLead {
  constructor(
    public readonly id: number,
    public readonly nombre: string,
    public readonly telefono: string,
    public readonly auto?: string | null,
    public readonly localidad?: string | null,
    public readonly cliente?: string | null, //  Nuevo campo
    public readonly comentarios?: string | null,
    public readonly source: string = "webhook",
    public readonly createdAt?: Date,
    public readonly updatedAt?: Date,
    public readonly fechaCreacion?: Date,
  ) {}

  /**
   * Valida que el lead tenga los datos mínimos requeridos
   */
  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (!this.nombre || this.nombre.trim().length === 0) {
      errors.push("El nombre es requerido");
    }

    if (!this.telefono || this.telefono.trim().length === 0) {
      errors.push("El teléfono es requerido");
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }

  /**
   * Normaliza el número de teléfono removiendo caracteres especiales
   */
  static normalizePhone(phone: string): string {
    return phone.replace(/[^\d]/g, "");
  }
}

client/src/components/RoleBasedRoute.tsx.content:
import { useAuth } from "@/lib/auth-context";
import { useLocation } from "wouter";
import { ReactNode } from "react";
import { Loader2, ShieldAlert } from "lucide-react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";

interface RoleBasedRouteProps {
  children: ReactNode;
  allowedRoles?: string[]; // ["admin", "gerente", "asesor"] por defecto
  requireAdmin?: boolean; // true = solo admin
}

/**
 * Componente que protege rutas basado en roles de usuario
 *
 * Uso:
 * <RoleBasedRoute requireAdmin>
 *   <AdminDashboard />
 * </RoleBasedRoute>
 *
 * <RoleBasedRoute allowedRoles={["gerente", "admin"]}>
 *   <PublicFeature />
 * </RoleBasedRoute>
 */
export function RoleBasedRoute({
  children,
  allowedRoles = ["admin", "gerente", "asesor"], // ✅ ACTUALIZADO
  requireAdmin = false,
}: RoleBasedRouteProps) {
  const { user, isAuthenticated, isLoading, logout } = useAuth();
  const [, setLocation] = useLocation();

  // Mostrar loading mientras se verifica la autenticación
  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="h-8 w-8 animate-spin mx-auto mb-4 text-primary" />
          <p className="text-sm text-muted-foreground">
            Verificando permisos...
          </p>
        </div>
      </div>
    );
  }

  // Redirigir a login si no está autenticado
  if (!isAuthenticated || !user) {
    setLocation("/login");
    return null;
  }

  // Verificar permisos de rol
  const userRole = user.role;
  const hasPermission = requireAdmin
    ? userRole === "admin"
    : allowedRoles.includes(userRole);

  // ✅ FUNCIÓN PARA OBTENER HOME SEGÚN ROL
  const getHomeRoute = (role: string): string => {
    if (role === "admin") return "/";
    if (role === "gerente") return "/user-home";
    if (role === "asesor") return "/asesor-home";
    return "/";
  };

  // Si no tiene permisos, mostrar página de acceso denegado
  if (!hasPermission) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-red-50 to-orange-50 dark:from-gray-900 dark:to-gray-800 p-4">
        <Card className="w-full max-w-md shadow-xl border-red-200">
          <CardHeader className="text-center">
            <div className="mx-auto mb-4 p-3 bg-red-100 dark:bg-red-900 rounded-full w-fit">
              <ShieldAlert className="h-12 w-12 text-red-600 dark:text-red-400" />
            </div>
            <CardTitle className="text-2xl">Acceso Denegado</CardTitle>
            <CardDescription>
              No tienes permisos para acceder a esta sección
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="p-4 bg-red-50 dark:bg-red-950 rounded-lg border border-red-200 dark:border-red-800">
              <p className="text-sm text-muted-foreground">
                <strong>Tu rol actual:</strong> {userRole}
              </p>
              <p className="text-sm text-muted-foreground mt-2">
                <strong>Roles permitidos:</strong>{" "}
                {requireAdmin ? "Administrador" : allowedRoles.join(", ")}
              </p>
            </div>

            <div className="flex gap-2">
              <Button
                variant="outline"
                className="flex-1"
                onClick={() => setLocation(getHomeRoute(userRole))} // ✅ ACTUALIZADO
              >
                Volver al Inicio
              </Button>
              <Button
                variant="destructive"
                className="flex-1"
                onClick={async () => {
                  await logout();
                  setLocation("/login");
                }}
              >
                Cerrar Sesión
              </Button>
            </div>

            <p className="text-xs text-center text-muted-foreground">
              Si crees que esto es un error, contacta al administrador del
              sistema.
            </p>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Si tiene permisos, renderizar el contenido
  return <>{children}</>;
