import { useState, useEffect, useRef, useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";

interface DashboardWebSocketHook {
  isConnected: boolean;
  connectionError: string | null;
  reconnectCount: number;
  isRefreshing: boolean;
}

/**
 * Hook específico para WebSocket del dashboard
 * Escucha eventos de refresh y actualiza las queries automáticamente
 */
export function useDashboardWebSocket(): DashboardWebSocketHook {
  const [isConnected, setIsConnected] = useState(false);
  const [connectionError, setConnectionError] = useState<string | null>(null);
  const [reconnectCount, setReconnectCount] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout>();
  const queryClient = useQueryClient();

  // Función para invalidar todas las queries del dashboard
  const refreshAllDashboardData = useCallback(() => {
    console.log('🔄 Refrescando todos los datos del dashboard tras evento WebSocket');

    // Activar el loading indicator
    console.log('✅ Activando isRefreshing = true');
    setIsRefreshing(true);

    // Invalidar queries principales del dashboard
    queryClient.invalidateQueries({ queryKey: ['/api/dashboard/datos-diarios-db'] });
    queryClient.invalidateQueries({ queryKey: ['/api/dashboard/datos-diarios'] });
    queryClient.invalidateQueries({ queryKey: ['/api/dashboard'] });
    queryClient.invalidateQueries({ queryKey: ['/api/dashboard/stats'] });
    queryClient.invalidateQueries({ queryKey: ['/api/dashboard/finanzas'] });
    queryClient.invalidateQueries({ queryKey: ['/api/meta-ads/campaigns'] });
    queryClient.invalidateQueries({ queryKey: ['/api/meta-ads/stats'] });
    queryClient.invalidateQueries({ queryKey: ['/api/campanas-comerciales'] });
    queryClient.invalidateQueries({ queryKey: ['/api/clientes'] });

    console.log('✅ Todas las queries del dashboard han sido invalidadas');

    // Desactivar el loading después de 30 segundos (máximo esperado)
    setTimeout(() => {
      setIsRefreshing(false);
    }, 30000);
  }, [queryClient]);

  const connect = useCallback(() => {
    // Limpiar conexión previa si existe
    if (wsRef.current) {
      wsRef.current.close();
    }

    try {
      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${protocol}//${window.location.host}/ws`;

      console.log(`🔗 Conectando WebSocket del dashboard: ${wsUrl}`);
      const ws = new WebSocket(wsUrl);
      wsRef.current = ws;

      ws.onopen = () => {
        console.log('🔗 WebSocket conectado para escuchar eventos del dashboard');
        setIsConnected(true);
        setConnectionError(null);
        setReconnectCount(0);

        // Registrar para recibir eventos del dashboard
        ws.send(JSON.stringify({
          type: 'register_dashboard_listener'
        }));
      };

      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);

          // Escuchar evento de refresh del dashboard
          if (data.type === 'dashboard_refresh') {
            console.log('📡 Evento dashboard_refresh recibido:', data);

            // Esperar un momento para que el backend termine de procesar
            setTimeout(() => {
              refreshAllDashboardData();
            }, 1000);
          }

          // Escuchar actualizaciones de campañas específicas
          if (data.type === 'campaign_update') {
            console.log('📡 Evento campaign_update recibido:', data);

            // Refresh específico para campañas
            setTimeout(() => {
              refreshAllDashboardData();
            }, 500);
          }

        } catch (error) {
          console.error('❌ Error parseando mensaje WebSocket:', error);
        }
      };

      ws.onclose = (event) => {
        console.log('🔗 WebSocket del dashboard desconectado:', event.code, event.reason);
        setIsConnected(false);

        // Solo intentar reconectar si no fue un cierre intencional
        if (event.code !== 1000) {
          const delay = Math.min(1000 * Math.pow(2, reconnectCount), 30000); // Backoff exponencial, máximo 30s
          console.log(`🔄 Reintentando conexión WebSocket en ${delay}ms (intento ${reconnectCount + 1})`);

          reconnectTimeoutRef.current = setTimeout(() => {
            setReconnectCount(prev => prev + 1);
            connect();
          }, delay);
        }
      };

      ws.onerror = (error) => {
        console.error('❌ Error en WebSocket del dashboard:', error);
        setConnectionError('Error de conexión WebSocket');
      };

    } catch (error) {
      console.error('❌ Error creando WebSocket:', error);
      setConnectionError('No se pudo crear la conexión WebSocket');
    }
  }, [reconnectCount, refreshAllDashboardData]);

  const disconnect = useCallback(() => {
    console.log('🔌 Desconectando WebSocket del dashboard...');

    // Limpiar timeout de reconexión
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }

    // Cerrar conexión WebSocket
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.close(1000, 'Desconexión intencional');
    }

    wsRef.current = null;
    setIsConnected(false);
    setConnectionError(null);
    setReconnectCount(0);
  }, []);

  // Efectos para gestión del ciclo de vida
  useEffect(() => {
    // Conectar al montar el componente
    connect();

    // Cleanup al desmontar
    return () => {
      disconnect();
    };
  }, []); // Sin dependencias para que solo se ejecute una vez

  // Reconectar cuando se regresa a la pestaña
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (!document.hidden && !isConnected) {
        console.log('🔄 Pestaña activa y WebSocket desconectado - reconectando...');
        connect();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [isConnected, connect]);

  // Reconectar cuando regresa la conexión a internet
  useEffect(() => {
    const handleOnline = () => {
      if (!isConnected) {
        console.log('🌐 Conexión a internet restaurada - reconectando WebSocket...');
        connect();
      }
    };

    window.addEventListener('online', handleOnline);
    return () => window.removeEventListener('online', handleOnline);
  }, [isConnected, connect]);

  return {
    isConnected,
    connectionError,
    reconnectCount,
    isRefreshing
  };
}

server/campaign-closure/presentation/con.content:
import { Request, Response } from 'express';
import { db } from '../../../db';
import { campanasComerciales, opLead, clientes } from '../../../../shared/schema';
import { eq, sql } from 'drizzle-orm';

/**
 * Controlador para reabrir campañas cerradas
 * Útil para testing y correcciones
 */
export class CampaignReopenController {

  /**
   * POST /api/campaign-closure/reopen/:id
   * Reabre una campaña cerrada, desasignando sus leads
   */
  async reopenCampaign(req: Request, res: Response): Promise<void> {
    const campaignId = parseInt(req.params.id);
    const requestId = `REOPEN-${Date.now()}`;

    console.log(`🔓 [${requestId}] Solicitud de reapertura para campaña ${campaignId}`);

    if (!campaignId || isNaN(campaignId)) {
      res.status(400).json({
        success: false,
        error: 'ID de campaña inválido'
      });
      return;
    }

    try {
      // 1. Verificar estado actual
      console.log(`📋 [${requestId}] Verificando estado actual...`);

      const currentStateResult = await db.execute<{
        id: number;
        numero_campana: string;
        cliente: string;
        fecha_fin: Date | null;
        cantidad_datos_solicitados: number;
        marca: string;
        zona: string;
      }>(sql`
        SELECT
          cc.id,
          cc.numero_campana,
          c.nombre_comercial as cliente,
          cc.fecha_fin,
          cc.cantidad_datos_solicitados,
          cc.marca,
          cc.zona
        FROM campanas_comerciales cc
        LEFT JOIN clientes c ON cc.cliente_id = c.id
        WHERE cc.id = ${campaignId}
      `);

      const currentState = currentStateResult.rows || currentStateResult;

      if (!currentState || currentState.length === 0) {
        console.error(`❌ [${requestId}] Campaña no encontrada`);
        res.status(404).json({
          success: false,
          error: 'Campaña no encontrada'
        });
        return;
      }

      const campaign = currentState[0];
      const wasClosed = !!campaign.fecha_fin;

      console.log(`📊 [${requestId}] Estado: ${wasClosed ? 'Cerrada' : 'Abierta'}`);

      if (!wasClosed) {
        console.log(`⚠️ [${requestId}] Campaña ya está abierta`);
        res.status(200).json({
          success: true,
          message: 'Campaña ya estaba abierta',
          alreadyOpen: true,
          campaign: {
            id: campaign.id,
            cliente: campaign.cliente,
            numero_campana: campaign.numero_campana,
            marca: campaign.marca,
            zona: campaign.zona,
            estado: 'Abierta'
          }
        });
        return;
      }

      // 2. Contar leads asignados
      console.log(`📊 [${requestId}] Contando leads asignados...`);

      const leadsCountResult = await db.execute<{ count: number }>(sql`
        SELECT COUNT(*)::int as count
        FROM op_lead
        WHERE campaign_id = ${campaignId}
      `);

      const leadsCount = leadsCountResult.rows || leadsCountResult;
      const assignedLeads = leadsCount[0]?.count || 0;
      console.log(`📧 [${requestId}] Leads asignados: ${assignedLeads}`);

      // 3. Desasignar leads
      console.log(`🔄 [${requestId}] Desasignando ${assignedLeads} leads...`);

      await db.execute(sql`
        UPDATE op_lead
        SET campaign_id = NULL
        WHERE campaign_id = ${campaignId}
      `);

      console.log(`✅ [${requestId}] Leads desasignados`);

      // 4. Reabrir campaña
      console.log(`🔓 [${requestId}] Reabriendo campaña...`);

      await db.execute(sql`
        UPDATE campanas_comerciales
        SET fecha_fin = NULL,
            updated_at = NOW()
        WHERE id = ${campaignId}
      `);

      console.log(`✅ [${requestId}] Campaña reabierta`);

      // 5. Verificar resultado
      const verificationResult = await db.execute<{
        fecha_fin: Date | null;
      }>(sql`
        SELECT fecha_fin
        FROM campanas_comerciales
        WHERE id = ${campaignId}
      `);

      const verification = verificationResult.rows || verificationResult;
      const reopened = !verification[0]?.fecha_fin;

      if (!reopened) {
        throw new Error('Verificación falló: fecha_fin no es NULL');
      }

      console.log(`🎉 [${requestId}] ÉXITO - Campaña reabierta exitosamente`);

      res.status(200).json({
        success: true,
        message: 'Campaña reabierta exitosamente',
        campaign: {
          id: campaign.id,
          cliente: campaign.cliente,
          numero_campana: campaign.numero_campana,
          marca: campaign.marca,
          zona: campaign.zona,
          cantidad_datos_solicitados: campaign.cantidad_datos_solicitados,
          estado: 'Abierta'
        },
        leadsUnassigned: assignedLeads,
        previousState: {
          fecha_fin: campaign.fecha_fin
        }
      });

    } catch (error: any) {
      console.error(`❌ [${requestId}] ERROR:`, error.message);
      console.error(error.stack);

      res.status(500).json({
        success: false,
        error: 'Error interno del servidor',
        message: error.message
      });
    }
  }

  /**
   * GET /api/campaign-closure/can-reopen/:id
   * Verifica si una campaña puede ser reabierta
   */
  async canReopen(req: Request, res: Response): Promise<void> {
    const campaignId = parseInt(req.params.id);

    if (!campaignId || isNaN(campaignId)) {
      res.status(400).json({
        canReopen: false,
        reason: 'ID de campaña inválido'
      });
      return;
    }

    try {
      const stateResult = await db.execute<{
        id: number;
        fecha_fin: Date | null;
        leads_asignados: number;
      }>(sql`
        SELECT
          cc.id,
          cc.fecha_fin,
          COUNT(ol.id)::int as leads_asignados
        FROM campanas_comerciales cc
        LEFT JOIN op_lead ol ON ol.campaign_id = cc.id
        WHERE cc.id = ${campaignId}
        GROUP BY cc.id, cc.fecha_fin
      `);

      const state = stateResult.rows || stateResult;

      if (!state || state.length === 0) {
        res.status(404).json({
          canReopen: false,
          reason: 'Campaña no encontrada'
        });
        return;
      }

      const campaign = state[0];
      const isClosed = !!campaign.fecha_fin;
      const hasLeads = campaign.leads_asignados > 0;

      res.status(200).json({
        canReopen: isClosed,
        reason: isClosed
          ? `Campaña cerrada con ${campaign.leads_asignados} leads asignados. Puede reabrirse.`
          : 'Campaña ya está abierta',
        campaign: {
          id: campaign.id,
          isClosed,
          leadsAsignados: campaign.leads_asignados,
          fechaFin: campaign.fecha_fin
        }
      });

    } catch (error: any) {
      res.status(500).json({
        canReopen: false,
        reason: 'Error verificando estado',
        error: error.message
      });
    }
  }
}

