            >
              Cancelar
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={confirmCloseCampaign}
              className="bg-gradient-to-r from-red-500 to-rose-600 hover:from-red-600 hover:to-rose-700 text-white shadow-lg border-0"
              disabled={isClosingCampaign}
            >
              {isClosingCampaign ? (
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
              ) : (
                <Power className="w-4 h-4 mr-2" />
              )}
              Cerrar Campaña
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Componente de progreso flotante - se muestra cuando hay una campaña cerrándose */}
      {Array.from(closingCampaigns).map(campaignKey => (
        <CampaignClosureProgress
          key={campaignKey}
          campaignKey={campaignKey}
          onComplete={() => {
            setClosingCampaigns(prev => {
              const newSet = new Set(prev);
              newSet.delete(campaignKey);
              return newSet;
            });
            // Refrescar datos
            queryClient.invalidateQueries({ queryKey: ['/api/dashboard/datos-diarios-db'] });
            queryClient.invalidateQueries({ queryKey: ['/api/dashboard/datos-diarios'] });
          }}
          onError={(error) => {
            setClosingCampaigns(prev => {
              const newSet = new Set(prev);
              newSet.delete(campaignKey);
              return newSet;
            });
          }}
        />
      ))}
    </div>
  );
}

