import { AvailableLead } from '../entities/CampaignClosure';
import { ILeadRepository } from '../interfaces/ILeadRepository';
import { extractBrandsFromCampaign, calculateLeadDistribution, validateBrandPercentages, BrandInfo } from '../../../../shared/utils/multi-brand-utils';

/**
 * Servicio especializado en asignación de leads
 * Maneja la lógica específica de asignar leads únicos a campañas
 */
export class LeadAssigner {
  constructor(private leadRepository: ILeadRepository) {}

  /**
   * NUEVO: Asigna leads con distribución por múltiples marcas según porcentajes
   */
  async assignLeadsWithMultiBrands(
    campaignData: any,
    clientName: string,
    zone: string,
    campaignId: number,
    targetCount: number
  ): Promise<{
    success: boolean;
    totalAssigned: number;
    brandDistribution: { [marca: string]: number };
    details: any[];
    mode: 'automatica' | 'manual';
  }> {
    try {
      console.log(`🎯 ASIGNACIÓN MULTI-MARCA INICIADA: ${targetCount} leads para campaña ${campaignId}`);

      // 1. Determinar modo de asignación
      const isAutomatic = campaignData.asignacionAutomatica === true;
      const mode = isAutomatic ? 'automatica' : 'manual';

      console.log(`⚙️ MODO DE ASIGNACIÓN: ${mode.toUpperCase()}`);

      if (isAutomatic) {
        return await this.assignLeadsAutomatically(campaignData, clientName, zone, campaignId, targetCount);
      } else {
        return await this.assignLeadsManually(campaignData, clientName, zone, campaignId, targetCount);
      }

    } catch (error: any) {
      console.error(`❌ Error en asignación multi-marca:`, error);
      throw new Error(`Multi-brand assignment failed: ${error.message}`);
    }
  }

  /**
   * MODO AUTOMÁTICO: Pool unificado ordenado cronológicamente (ignora porcentajes)
   */
  private async assignLeadsAutomatically(
    campaignData: any,
    clientName: string,
    zone: string,
    campaignId: number,
    targetCount: number
  ): Promise<{
    success: boolean;
    totalAssigned: number;
    brandDistribution: { [marca: string]: number };
    details: any[];
    mode: 'automatica';
  }> {
    console.log(`🤖 MODO AUTOMÁTICO: Pool unificado cronológico`);

    // 1. Extraer marcas (TODAS, sin considerar porcentajes)
    const brands = extractBrandsFromCampaign(campaignData, true); // automaticMode = true
    const brandNames = brands.map(b => b.marca);

    console.log(`🏷️ Marcas disponibles: ${brandNames.join(', ')}`);
    console.log(`❌ Porcentajes IGNORADOS en modo automático`);

    // 2. Obtener pool unificado ordenado cronológicamente
    const availableLeads = await this.leadRepository.getUnifiedLeadsPoolChronologically(
      clientName,
      brandNames,
      zone,
      campaignId,
      targetCount
    );

    console.log(`📊 Pool unificado disponible: ${availableLeads.length}/${targetCount} leads`);

    // 3. Asignar en bloque cronológico
    const result = await this.leadRepository.assignLeadsChronologically(
      availableLeads,
      campaignId
    );

    // 4. Construir detalles por marca
    const details = brandNames.map(marca => ({
      marca,
      porcentaje: 0, // Ignorado en modo automático
      solicitados: 0, // No aplica en modo automático
      asignados: result.brandDistribution[marca] || 0,
      exito: true // Siempre exitoso si hay leads
    }));

    const success = result.assigned === targetCount;

    console.log(`✅ ASIGNACIÓN AUTOMÁTICA COMPLETADA:`);
    console.log(`   Total asignado: ${result.assigned}/${targetCount}`);
    console.log(`   Distribución real:`, result.brandDistribution);
    console.log(`   Éxito: ${success ? '✅' : '❌'} (${success ? 'completo' : 'parcial'})`);

    return {
      success,
      totalAssigned: result.assigned,
      brandDistribution: result.brandDistribution,
      details,
      mode: 'automatica'
    };
  }

  /**
   * MODO MANUAL: Asignación por porcentajes exactos
   */
  private async assignLeadsManually(
    campaignData: any,
    clientName: string,
    zone: string,
    campaignId: number,
    targetCount: number
  ): Promise<{
    success: boolean;
    totalAssigned: number;
    brandDistribution: { [marca: string]: number };
    details: any[];
    mode: 'manual';
  }> {
    console.log(`📊 MODO MANUAL: Asignación por porcentajes exactos`);

    // 1. Extraer y validar configuración de marcas (solo con porcentaje > 0)
    const brands = extractBrandsFromCampaign(campaignData, false); // automaticMode = false
    const validation = validateBrandPercentages(brands);

    if (!validation.valid) {
      throw new Error(`Configuración inválida de marcas: ${validation.error}`);
    }

    console.log(`🏷️ Marcas configuradas: ${brands.length}`);
    brands.forEach((brand, i) => {
      console.log(`   ${i + 1}. ${brand.marca}: ${brand.porcentaje}%`);
    });

    // 2. Calcular distribución exacta por porcentajes
    const distribution = calculateLeadDistribution(targetCount, brands);
    console.log(`📊 Distribución exacta:`, distribution);

    // 3. Asignar por cada marca individual (porcentajes exactos)
    const assignmentDetails = [];
    let totalAssigned = 0;

    for (const brand of brands) {
      const leadsForBrand = distribution[brand.marca];

      if (leadsForBrand > 0) {
        console.log(`\n🎯 Asignando ${leadsForBrand} leads para marca: ${brand.marca} (${brand.porcentaje}%)`);

        const result = await this.assignLeadsToTarget(
          clientName,
          brand.marca,
          zone,
          campaignId,
          leadsForBrand
        );

        const exactMatch = result.assigned === leadsForBrand;

        assignmentDetails.push({
          marca: brand.marca,
          porcentaje: brand.porcentaje,
          solicitados: leadsForBrand,
          asignados: result.assigned,
          exito: exactMatch
        });

        totalAssigned += result.assigned;

        console.log(`   ${exactMatch ? '✅' : '❌'} ${brand.marca}: ${result.assigned}/${leadsForBrand} leads`);

        // En modo manual, el fallo de una marca falla toda la operación INMEDIATAMENTE
        if (!exactMatch) {
          console.log(`❌ ERROR CRÍTICO: No se pudo asignar porcentaje exacto para ${brand.marca}`);
          throw new Error(`Modo manual falló: No se pueden asignar ${leadsForBrand} leads exactos para ${brand.marca} (solo ${result.assigned} disponibles)`);
        }
      } else {
        assignmentDetails.push({
          marca: brand.marca,
          porcentaje: brand.porcentaje,
          solicitados: 0,
          asignados: 0,
          exito: true
        });
      }
    }

    // 4. Evaluar éxito: debe asignar EXACTAMENTE lo solicitado por porcentaje
    const exactSuccess = totalAssigned === targetCount &&
                        assignmentDetails.every(detail => detail.exito);

    console.log(`\n📊 RESUMEN MODO MANUAL:`);
    console.log(`   Total asignado: ${totalAssigned}/${targetCount}`);
    console.log(`   Porcentajes exactos: ${exactSuccess ? '✅' : '❌'}`);

    // 5. Construir distribución final por marca
    const brandDistribution: { [marca: string]: number } = {};
    assignmentDetails.forEach(detail => {
      brandDistribution[detail.marca] = detail.asignados;
    });

    return {
      success: exactSuccess,
      totalAssigned,
      brandDistribution,
      details: assignmentDetails,
      mode: 'manual'
    };
  }

  /**
   * EXISTENTE: Asigna leads usando función atómica que previene race conditions
   */
  async assignLeadsToTarget(
    clientName: string,
    brandName: string,
    zone: string,
    campaignId: number,
    targetCount: number
  ): Promise<{
    assigned: number;
    finalLeadDate?: Date;
    leads: AvailableLead[];
  }> {
    try {
      console.log(`🎯 ASIGNACIÓN ATÓMICA INICIADA: ${targetCount} leads para campaña ${campaignId}`);
      console.log(`📋 Filtros: cliente=${clientName}, marca=${brandName}, zona=${zone}`);

      // USAR NUEVA FUNCIÓN ATÓMICA - Una sola operación, sin race conditions
      const result = await this.leadRepository.assignLeadsAtomically(
        clientName,
        brandName,
        zone,
        campaignId,
        targetCount
      );

      console.log(`✅ ASIGNACIÓN ATÓMICA COMPLETADA:`);
      console.log(`   📊 Leads asignados: ${result.assigned}`);
      console.log(`   🔢 Conteo exacto verificado: ${result.exactCountVerified ? '✅' : '⚠️'}`);
      console.log(`   📅 Fecha final: ${result.finalLeadDate?.toISOString()}`);

      // Verificar que la asignación fue exitosa
      if (!result.exactCountVerified) {
        throw new Error(`Error crítico: conteo inexacto en asignación atómica`);
      }

      return {
        assigned: result.assigned,
        finalLeadDate: result.finalLeadDate,
        leads: result.leads
      };
    } catch (error: any) {
      console.error(`❌ ERROR EN ASIGNACIÓN ATÓMICA:`, error);
      throw new Error(`Atomic lead assignment failed: ${error.message}`);
    }
  }

  /**
   * Valida que los leads están correctamente asignados
   */
  async validateAssignment(campaignId: number, expectedCount: number): Promise<boolean> {
    try {
      const assignedLeads = await this.leadRepository.getLeadsAssignedToCampaign(campaignId);
      const actualCount = assignedLeads.length;

      console.log(`✅ Validación: esperados ${expectedCount}, asignados ${actualCount}`);

      return actualCount === expectedCount;
    } catch (error: any) {
      console.error(`❌ Error validando asignación:`, error);
      return false;
    }
  }

  /**
   * Obtiene estadísticas de leads disponibles por cliente
   */
  async getAvailabilityStats(clientName: string, brandName: string, zone: string): Promise<{
    total: number;
    available: number;
    assigned: number;
  }> {
    try {
      const allLeads = await this.leadRepository.getAvailableLeadsForClient(clientName, brandName, zone);
      const total = allLeads.length;

      let assigned = 0;
      for (const lead of allLeads) {
        const isAssigned = await this.leadRepository.isLeadAssigned(lead.id);
        if (isAssigned) assigned++;
      }

      const available = total - assigned;

      return { total, available, assigned };
    } catch (error: any) {
      console.error(`❌ Error obteniendo estadísticas:`, error);
      return { total: 0, available: 0, assigned: 0 };
    }
  }
}

server/optimized-route.ts.content:
// ENDPOINT OPTIMIZADO PARA /api/dashboard/datos-diarios-db
// Usa vista materializada para 10x mejor performance
// Mantiene TODA la lógica de deduplicación original

import type { Express } from "express";
import { sql } from 'drizzle-orm';
import { calculateDatosEnviadosPercentage, calculateFaltantesAEnviar, calculatePorcentajeDesvio } from '../shared/utils/percentage-utils';

export function registerOptimizedRoute(app: Express) {

  // NUEVO ENDPOINT OPTIMIZADO que reemplaza el actual
  app.get('/api/dashboard/datos-diarios-db-optimized', async (req, res) => {
    try {
      console.log('🚀 [OPTIMIZED] Iniciando consulta desde vista materializada...');

      const { db } = await import('./db');
      const { storage } = await import('./storage');

      const startTime = Date.now();

      // STEP 1: Obtener datos base desde vista materializada (ultra rápido)
      const campanasBaseResult = await db.execute(sql`
        SELECT
          mv.*,
          -- Obtener CPL desde storage si existe
          COALESCE(
            (SELECT cpl FROM dashboard_manual_values
             WHERE cliente_index = mv.cliente_id
             LIMIT 1),
            0
          ) as stored_cpl
        FROM mv_dashboard_datos_diarios mv
        ORDER BY mv.id DESC
      `);

      console.log(`⚡ Vista materializada consultada en: ${Date.now() - startTime}ms`);
      console.log('🔍 Debug - Tipo de resultado:', typeof campanasBaseResult);
      console.log('🔍 Debug - Es array:', Array.isArray(campanasBaseResult));
      console.log('🔍 Debug - Propiedades:', Object.keys(campanasBaseResult || {}));

      // CORRECCIÓN: Drizzle con postgres-js retorna objeto con propiedad rows
      let campanasBase = [];
      if (campanasBaseResult && campanasBaseResult.rows && Array.isArray(campanasBaseResult.rows)) {
        campanasBase = campanasBaseResult.rows;
      } else if (Array.isArray(campanasBaseResult)) {
        campanasBase = campanasBaseResult;
      } else {
        console.error('❌ Estructura de resultado no reconocida:', campanasBaseResult);
        console.error('❌ Tipo:', typeof campanasBaseResult);
        console.error('❌ Keys:', Object.keys(campanasBaseResult || {}));
        throw new Error('No se pudo procesar el resultado de la consulta');
      }

      console.log(`📊 Debug - Registros encontrados: ${campanasBase.length}`);

      // Verificar que el resultado sea iterable
      if (!Array.isArray(campanasBase)) {
        console.error('❌ Error: campanasBase no es un array:', typeof campanasBase);
        throw new Error('campanasBase no es iterable');
      }

      // STEP 2: Procesar datos manteniendo lógica original
      const processedData = [];

      for (const campana of campanasBase) {
        try {
          // Usar datos precalculados de la vista materializada (convertir a números)
          const enviadosFinales = Number(campana.enviados) || 0;
          const totalDuplicados = Number(campana.total_duplicados) || 0;

          // Identificadores compatibles con frontend
          const clienteIdentificador = `${campana.marca.toUpperCase()} ${campana.numero_campana}`;
          const clienteNombreReal = campana.nombre_cliente || clienteIdentificador;

          // Calcular métricas usando utilidad centralizada
          const cantidadSolicitados = campana.cantidad_datos_solicitados || 0;
          const percentageResult = calculateDatosEnviadosPercentage(enviadosFinales, cantidadSolicitados);
          const porcentajeDatosEnviados = percentageResult.percentage;
          const faltantesAEnviar = calculateFaltantesAEnviar(enviadosFinales, cantidadSolicitados);

          // CPL desde storage (misma lógica que endpoint original)
          const { storage } = await import('./storage');
          const cplValue = await storage.getCplByClienteAndCampana(
            clienteNombreReal,
            campana.numero_campana.toString()
          ) || 0;

          console.log(`🔍 [CPL DEBUG] Cliente: ${clienteNombreReal}, Campaña: ${campana.numero_campana}, CPL: ${cplValue}`);

          // Verificar si hay campaña anterior abierta (misma lógica)
          const tieneCampanaAnterior = await verificarCampanaAnterior(campana, db);

          // Aplicar guiones si hay campaña anterior abierta (mantener tipos originales)
          let enviadosDisplay: string | number = enviadosFinales;  // Número original
          let duplicadosDisplay: string | number = totalDuplicados; // Número original

          if (tieneCampanaAnterior) {
            enviadosDisplay = "-";
            duplicadosDisplay = "-";
          }

          // Calcular entregados por día
          const entregadosPorDia = (() => {
            if (tieneCampanaAnterior) return "-";

            const fechaInicio = campana.fecha_campana ? new Date(campana.fecha_campana) : new Date();
            const fechaReferencia = campana.fecha_fin ? new Date(campana.fecha_fin) : new Date();
            const diasTranscurridos = Math.max(1, Math.ceil((fechaReferencia.getTime() - fechaInicio.getTime()) / (1000 * 60 * 60 * 24)));

            return enviadosFinales / diasTranscurridos;
          })();

          // Record compatible con frontend original
          const record = {
            campaignId: campana.id,
            cliente: clienteIdentificador,
            clienteNombre: clienteNombreReal,
            zona: campana.zona,
            enviados: typeof enviadosDisplay === 'string' ? enviadosDisplay : Number(enviadosDisplay),
            cantidadDatosSolicitados: cantidadSolicitados,
            porcentajeDatosEnviados,
            faltantesAEnviar,
            numeroCampana: campana.numero_campana,
            cpl: Number(cplValue),
            marca: campana.marca,
            fechaCampana: campana.fecha_campana,
            fechaFin: campana.fecha_fin,
            fechaFinReal: campana.fecha_fin,
            facturacionBruta: campana.facturacion_bruta,
            pedidosPorDia: campana.pedidos_por_dia ?? 0,
            pedidosTotal: cantidadSolicitados,
            faltantes: tieneCampanaAnterior ? "-" : faltantesAEnviar,
            entregadosPorDia: entregadosPorDia,
            inversionRealizada: tieneCampanaAnterior ? "-" : (enviadosFinales * cplValue),
            inversionPendiente: tieneCampanaAnterior ? "-" : (faltantesAEnviar * cplValue),
            estado: campana.fecha_fin ? 'Finalizada' : 'En proceso',
            duplicados: typeof duplicadosDisplay === 'string' ? duplicadosDisplay : Number(duplicadosDisplay),
            // Nuevos campos de la vista materializada
            diasProcesados: 0, // Calculado en frontend
            porcentajeDesvio: tieneCampanaAnterior ? 0 : calculatePorcentajeDesvio(
              campana.pedidos_por_dia ?? 0,
              typeof entregadosPorDia === 'number' ? entregadosPorDia : 0
            ),
            ventaPorCampana: 0, // Desde storage si existe
            esSuperior100: porcentajeDatosEnviados > 100
          };

          processedData.push(record);

        } catch (campaignError) {
          console.error(`❌ Error procesando campaña ${campana.numero_campana}:`, campaignError);
        }
      }

      const totalTime = Date.now() - startTime;
      console.log(`🎯 [OPTIMIZED] Query completada en: ${totalTime}ms (vs ~37000ms original)`);
      console.log(`📊 [OPTIMIZED] Registros procesados: ${processedData.length}`);

      res.json(processedData);

    } catch (error) {
      console.error('❌ [OPTIMIZED] Error en endpoint optimizado:', error);
      res.status(500).json({ error: 'Error en consulta optimizada', details: error.message });
    }
  });

  // ENDPOINT PARA REFRESCAR VISTA MATERIALIZADA MANUALMENTE
  app.post('/api/dashboard/refresh-materialized-view', async (req, res) => {
    try {
      console.log('🔄 Refrescando vista materializada...');

      const { db } = await import('./db');
      const startTime = Date.now();

      await db.execute(sql`REFRESH MATERIALIZED VIEW CONCURRENTLY mv_dashboard_datos_diarios`);

      const refreshTime = Date.now() - startTime;
      console.log(`✅ Vista materializada refrescada en: ${refreshTime}ms`);

      res.json({
        success: true,
        message: `Vista materializada refrescada en ${refreshTime}ms`,
        refreshTime
      });

    } catch (error) {
      console.error('❌ Error refrescando vista materializada:', error);
      res.status(500).json({ error: 'Error al refrescar vista materializada' });
    }
  });
}

// Función helper para verificar campaña anterior abierta
async function verificarCampanaAnterior(campana: any, db: any): Promise<boolean> {
  try {
    const result = await db.execute(sql`
      SELECT COUNT(*) as count
      FROM mv_dashboard_datos_diarios
      WHERE cliente_id = ${campana.cliente_id}
        AND marca = ${campana.marca}
        AND zona = ${campana.zona}
        AND numero_campana < ${campana.numero_campana}
        AND fecha_fin IS NULL
      LIMIT 1
    `);

    return (result[0]?.count || 0) > 0;
  } catch (error) {
    console.error('Error verificando campaña anterior:', error);
    return false;
  }
}

// INSTRUCCIONES DE USO:
/*
1. Importar en routes.ts:
   import { registerOptimizedRoute } from './optimized-route';
   registerOptimizedRoute(app);

2. En el frontend, cambiar la URL:
   queryKey: ['/api/dashboard/datos-diarios-db-optimized']

3. Para refrescar datos manualmente:
   POST /api/dashboard/refresh-materialized-view

4. Performance esperada:
   - Tiempo original: ~37000ms
   - Tiempo optimizado: ~500-1000ms
   - Mejora: 97% más rápido

5. Beneficios:
   ✅ Mantiene TODA la lógica de deduplicación
   ✅ Compatible con frontend existente
   ✅ 97% más rápido
   ✅ Cache inteligente con vista materializada
   ✅ Refresh manual disponible
*/

