  adsetName: string;
  campaignId: string;
  campaignName: string;
  spend: number;
  accountCurrency: string;
  impressions: number;
  clicks: number;
  cpc: number;
  cpm: number;
  dateStart: string;
  dateStop: string;
  lastUpdated: Date;
  costPerResult?: number;
  results?: number; // Cantidad de resultados/conversiones
  actions?: any;
  costPerActionType?: any;
  effectiveStatus?: string; // Estado actual del adset (ACTIVE, PAUSED, etc.)
  isActive?: boolean; // Helper para verificar si está activo
}

interface MetaStats {
  totalSpend: number;
  totalCampaigns: number;
  avgCPC: number;
  avgCPM: number;
  isConnected: boolean;
  lastSync: Date | null;
}

// Interfaces para el informe de auditoría
interface AuditReport {
  periodo: string;
  cambios: {
    adsets: {
      total: number;
      nuevos: number;
      modificados: number;
      pausados: number;
    };
    anuncios?: {
      total: number;
      nuevos: number;
      modificados: number;
      pausados: number;
    };
    detalles: Array<{
      tipo: string;
      nombre: string;
      descripcion: string;
      fecha: string;
    }>;
  };
  costes: {
    gastoTotal: number;
    gastoDiario: number;
    cpcPromedio: number;
    cpmPromedio: number;
    moneda: string;
  };
  resultados: {
    impresiones: number;
    clics: number;
    ctr: number;
    alcance: number;
    frecuencia: number;
  };
  resumen: string;
}

interface AuditFilters {
  fechaInicio: string;
  fechaFin: string;
  campanaId: string;
  rangoRapido: string;
}

export default function MetaAdsDashboard() {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Estado para filtros de campañas
  const [campaignFilters, setCampaignFilters] = useState({
    fechaInicio: format(new Date(), 'yyyy-MM-dd'),
    fechaFin: format(new Date(), 'yyyy-MM-dd'),
    nombreCampana: '',
    rangoRapido: 'hoy'
  });

  // Estado para filtro de conjuntos de anuncios
  const [adsetFilter, setAdsetFilter] = useState('');

  // Estado para filtros globales de fechas
  const [globalDateFilters, setGlobalDateFilters] = useState({
    fechaInicio: format(new Date(), 'yyyy-MM-dd'),
    fechaFin: format(new Date(), 'yyyy-MM-dd')
  });

  // Estado para manejar campañas expandidas y sus adsets
  const [expandedCampaigns, setExpandedCampaigns] = useState<Set<string>>(new Set());
  const [campaignAdsets, setCampaignAdsets] = useState<Record<string, MetaAdset[]>>({});

  // Estado para el módulo de auditoría
  const [auditFilters, setAuditFilters] = useState<AuditFilters>({
    fechaInicio: format(subDays(new Date(), 7), 'yyyy-MM-dd'),
    fechaFin: format(new Date(), 'yyyy-MM-dd'),
    campanaId: '',
    rangoRapido: 'ult7dias'
  });
  const [auditReport, setAuditReport] = useState<AuditReport | null>(null);

  // Función para aplicar rango rápido para campañas
  const applyCampaignQuickRange = (rangoRapido: string) => {
    const now = new Date();
    const today = format(now, 'yyyy-MM-dd');
    const yesterday = format(subDays(now, 1), 'yyyy-MM-dd');

    let fechaInicio = '';
    let fechaFin = '';

    switch (rangoRapido) {
      case 'hoy':
        fechaInicio = today;
        fechaFin = today;
        break;
      case 'ayer':
        fechaInicio = yesterday;
        fechaFin = yesterday;
        break;
      case 'ayer_hoy':
        fechaInicio = yesterday;
        fechaFin = today;
        break;
      case 'ult7dias':
        fechaInicio = format(subDays(now, 6), 'yyyy-MM-dd');
        fechaFin = today;
        break;
      case 'ult14dias':
        fechaInicio = format(subDays(now, 13), 'yyyy-MM-dd');
        fechaFin = today;
        break;
      case 'ult30dias':
        fechaInicio = format(subDays(now, 29), 'yyyy-MM-dd');
        fechaFin = today;
        break;
      case 'ult6meses':
        fechaInicio = format(subDays(now, 180), 'yyyy-MM-dd');
        fechaFin = today;
        break;
      case 'ult1ano':
        fechaInicio = format(subDays(now, 365), 'yyyy-MM-dd');
        fechaFin = today;
        break;
      default:
        return; // No cambiar fechas si es personalizado
    }

    // Actualizar tanto los filtros de campaña como los filtros globales
    setCampaignFilters(prev => ({
      ...prev,
      rangoRapido,
      fechaInicio,
      fechaFin
    }));

