                              {campaign.results && campaign.results > 0 
                                ? formatNumber(campaign.results)
                                : <span className="text-gray-400">0</span>
                              }
                            </td>
                            <td className="text-center p-3">
                              {formatCurrency(campaign.cpc, campaign.accountCurrency)}
                            </td>
                            <td className="text-center p-3">
                              {formatCurrency(campaign.cpm, campaign.accountCurrency)}
                            </td>
                            <td className="text-center p-3">
                              <Badge 
                                variant="default" 
                                className={
                                  campaign.isActive 
                                    ? "bg-green-100 text-green-800" 
                                    : "bg-red-100 text-red-800"
                                }
                              >
                                {campaign.isActive ? "Activa" : "Desactivado"}
                              </Badge>
                            </td>
                          </tr>
                        );

                        const adsetRows: JSX.Element[] = [];
                        if (expandedCampaigns.has(campaign.campaignId) && campaignAdsets[campaign.campaignId]) {
                          campaignAdsets[campaign.campaignId]
                            .filter((adset) => {
                              // Filtrar por nombre de conjunto de anuncios
                              const adsetNameMatch = !adsetFilter || 
                                adset.adsetName.toLowerCase().includes(adsetFilter.toLowerCase());
                              return adsetNameMatch;
                            })
                            .forEach((adset, index) => {
                            adsetRows.push(
                              <tr key={`${campaign.campaignId}-adset-${adset.adsetId}`} className="border-b border-gray-50 hover:bg-orange-25 bg-orange-10">
                                <td className="p-3 pl-12">
                                  <div className="flex items-center gap-2">
                                    <div className="w-4 h-4 flex items-center justify-center">
                                      <div className="w-2 h-2 bg-orange-400 rounded-full"></div>
                                    </div>
                                    <div>
                                      <div className="font-medium text-orange-700">🎯 {adset.adsetName}</div>
                                      <div className="text-xs text-gray-500">Adset ID: {adset.adsetId}</div>
                                    </div>
                                  </div>
                                </td>
                                <td className="text-center p-3 text-green-600">
                                  {formatCurrency(adset.spend, adset.accountCurrency)}
                                </td>
                                <td className="text-center p-3 text-purple-600">
                                  {adset.costPerResult && adset.costPerResult > 0 
                                    ? formatCurrency(adset.costPerResult, adset.accountCurrency)
                                    : <span className="text-gray-400">N/A</span>
                                  }
                                </td>
                                <td className="text-center p-3 text-blue-600">
                                  {adset.results && adset.results > 0 
                                    ? formatNumber(adset.results)
                                    : <span className="text-gray-400">0</span>
                                  }
                                </td>
                                <td className="text-center p-3">
                                  {formatCurrency(adset.cpc, adset.accountCurrency)}
                                </td>
                                <td className="text-center p-3">
                                  {formatCurrency(adset.cpm, adset.accountCurrency)}
                                </td>
                                <td className="text-center p-3">
                                  <Badge variant="outline" className="bg-orange-50 text-orange-700 border-orange-200">
                                    Conjunto
                                  </Badge>
                                </td>
                              </tr>
                            );
                          });
                        }

                        return [campaignRow, ...adsetRows];
                      })
                    }
                  </tbody>
                </table>
              </div>
            ) : (
              <div className="text-center py-8 text-gray-500">
                <BarChart3 className="h-12 w-12 mx-auto mb-4 text-gray-300" />
                <p>No hay campañas disponibles</p>
                <p className="text-sm">Sincroniza para cargar datos de Meta Ads</p>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Módulo de Informes de Auditoría */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5 text-purple-500" />
              Informes de Auditoría
            </CardTitle>
            <CardDescription>
              Genera informes detallados de cambios en conjuntos de anuncios y resultados de campañas
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {/* Filtros */}
              <div className="space-y-4 p-4 border border-gray-200 rounded-lg bg-gray-50">


                {/* Filtros de Fecha Personalizada */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <label className="block text-sm font-medium mb-2">Fecha Inicio</label>
                    <input
                      type="date"
                      className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      value={auditFilters.fechaInicio}
                      onChange={(e) => setAuditFilters(prev => ({ ...prev, fechaInicio: e.target.value, rangoRapido: 'personalizado' }))}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-2">Fecha Fin</label>
                    <input
                      type="date"
                      className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      value={auditFilters.fechaFin}
                      onChange={(e) => setAuditFilters(prev => ({ ...prev, fechaFin: e.target.value, rangoRapido: 'personalizado' }))}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-2">Campaña</label>
                    <select
                      className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      value={auditFilters.campanaId}
                      onChange={(e) => setAuditFilters(prev => ({ ...prev, campanaId: e.target.value }))}
                    >
                      <option value="">Todas las campañas</option>
                      {campaigns?.map((campaign) => (
                        <option key={campaign.campaignId} value={campaign.campaignId}>
                          {campaign.campaignName}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {/* Botón Generar Informe */}
              <div className="flex justify-center gap-3">
                <Button
                  onClick={generateAuditReport}
                  disabled={generateReportMutation.isPending || !auditFilters.fechaInicio || !auditFilters.fechaFin}
                  className="bg-gradient-to-r from-purple-500 to-blue-600 hover:from-purple-600 hover:to-blue-700"
                >
                  {generateReportMutation.isPending ? (
                    <RefreshCw className="h-4 w-4 animate-spin mr-2" />
                  ) : (
                    <FileText className="h-4 w-4 mr-2" />
                  )}
                  Generar Informe
                </Button>

                {auditReport && (
                  <Button
                    onClick={downloadReport}
                    variant="outline"
                    className="border-green-200 hover:bg-green-50 text-green-600"
                  >
                    <Download className="h-4 w-4 mr-2" />
                    Descargar Informe
                  </Button>
                )}
              </div>

              {/* Resultado del Informe */}
              {auditReport && (
                <div className="space-y-4 mt-6">
                  <div className="border-t pt-4">
                    <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                      <Activity className="h-5 w-5 text-green-500" />
                      Informe de Auditoría - {auditReport.periodo}
                    </h3>

                    {/* Cambios en Conjuntos y Anuncios */}
                    {auditReport.cambios && auditReport.cambios.adsets ? (
                      <Card className="mb-4">
                        <CardHeader>
                          <CardTitle className="text-base">Auditoría de Cambios en Conjuntos y Anuncios</CardTitle>
                        </CardHeader>
                        <CardContent>
                          <div className="space-y-3">
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-center">
                              <div className="p-3 bg-blue-50 rounded-lg">
                                <div className="text-2xl font-bold text-blue-600">{auditReport.cambios.adsets.total || 0}</div>
                                <div className="text-sm text-gray-600">Conjuntos Activos</div>
                              </div>
                              <div className="p-3 bg-green-50 rounded-lg">
                                <div className="text-2xl font-bold text-green-600">{auditReport.cambios.adsets.nuevos || 0}</div>
                                <div className="text-sm text-gray-600">Nuevos</div>
                              </div>
                              <div className="p-3 bg-yellow-50 rounded-lg">
                                <div className="text-2xl font-bold text-yellow-600">{auditReport.cambios.adsets.modificados || 0}</div>
                                <div className="text-sm text-gray-600">Modificados</div>
                              </div>
                              <div className="p-3 bg-red-50 rounded-lg">
                                <div className="text-2xl font-bold text-red-600">{auditReport.cambios.adsets.pausados || 0}</div>
                                <div className="text-sm text-gray-600">Pausados</div>
                              </div>
                            </div>

                            {auditReport.cambios.detalles && auditReport.cambios.detalles.length > 0 && (
                              <div className="mt-4">
                                <h4 className="font-medium mb-2">Cambios Detectados:</h4>
                                <div className="space-y-2 max-h-40 overflow-y-auto">
                                  {auditReport.cambios.detalles.map((cambio, index) => (
                                    <div key={index} className="p-2 bg-gray-50 rounded text-sm">
                                      <div className="font-medium">{cambio.tipo}: {cambio.nombre}</div>
                                      <div className="text-gray-600">{cambio.descripcion}</div>
                                      <div className="text-xs text-gray-500">{cambio.fecha}</div>
                                    </div>
                                  ))}
                                </div>
                              </div>
                            )}
                          </div>
                        </CardContent>
                      </Card>
                    ) : null}

                    {/* Informe Completo Redactado - Siempre Visible */}
                    <Card className="mb-4">
                      <CardHeader>
                        <CardTitle className="text-base flex items-center gap-2">
                          <FileText className="h-5 w-5 text-blue-600" />
                          Informe Completo de Auditoría
                        </CardTitle>
                      </CardHeader>
                      <CardContent>
                        <div className="bg-gradient-to-br from-gray-50 to-blue-50 p-6 border border-gray-200 rounded-lg shadow-sm">
                          <div className="bg-white p-6 rounded-lg shadow-inner">
                            <pre className="whitespace-pre-wrap font-sans text-sm leading-relaxed text-gray-800">
                              {generateFullReportText(auditReport)}
                            </pre>
                          </div>
                        </div>
                      </CardContent>
                    </Card>

                    {/* Costes y Resultados */}
                    {auditReport.costes && auditReport.resultados && (
                      <Card>
                        <CardHeader>
                          <CardTitle className="text-base">Costes y Resultados</CardTitle>
                        </CardHeader>
                        <CardContent>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {/* Métricas de Coste */}
                            <div>
                              <h4 className="font-medium mb-3 text-gray-700">Inversión Total</h4>
                              <div className="space-y-2">
                                <div className="flex justify-between">
                                  <span>Gasto Total:</span>
                                  <span className="font-semibold text-green-600">
                                    {formatCurrency(auditReport.costes.gastoTotal || 0, auditReport.costes.moneda || 'ARS')}
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>Gasto Promedio Diario:</span>
                                  <span className="font-medium">
                                    {formatCurrency(auditReport.costes.gastoDiario || 0, auditReport.costes.moneda || 'ARS')}
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>CPC Promedio:</span>
                                  <span className="font-medium">
                                    {formatCurrency(auditReport.costes.cpcPromedio || 0, auditReport.costes.moneda || 'ARS')}
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>CPM Promedio:</span>
                                  <span className="font-medium">
                                    {formatCurrency(auditReport.costes.cpmPromedio || 0, auditReport.costes.moneda || 'ARS')}
                                  </span>
                                </div>
                              </div>
                            </div>

                            {/* Métricas de Resultado */}
                            <div>
                              <h4 className="font-medium mb-3 text-gray-700">Resultados Obtenidos</h4>
                              <div className="space-y-2">
                                <div className="flex justify-between">
                                  <span>Impresiones:</span>
                                  <span className="font-semibold text-blue-600">
                                    {formatNumber(auditReport.resultados.impresiones || 0)}
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>Clics:</span>
                                  <span className="font-semibold text-purple-600">
                                    {formatNumber(auditReport.resultados.clics || 0)}
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>CTR:</span>
                                  <span className="font-medium">
                                    {(auditReport.resultados.ctr || 0).toFixed(2)}%
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>Alcance:</span>
                                  <span className="font-medium">
                                    {formatNumber(auditReport.resultados.alcance || 0)}
                                  </span>
                                </div>
                                <div className="flex justify-between">
                                  <span>Frecuencia:</span>
                                  <span className="font-medium">
                                    {(auditReport.resultados.frecuencia || 0).toFixed(2)}
                                  </span>
                                </div>
                              </div>
                            </div>
                          </div>

                          {/* Resumen Ejecutivo */}
                          <div className="mt-6 p-4 bg-gradient-to-r from-blue-50 to-purple-50 rounded-lg">
                            <h4 className="font-semibold mb-2 text-gray-800">Resumen Ejecutivo</h4>
                            <p className="text-sm text-gray-700 leading-relaxed">
                              {auditReport.resumen}
                            </p>
                          </div>
                        </CardContent>
                      </Card>
                    )}
                  </div>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

client/src/pages/clientes-op-leads.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { CalendarDays, Users, Phone, Mail, MapPin, Building } from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";

interface ClienteOpLead {
  cliente: string;
  marca: string;
  localizacion: string;
  total_leads: number;
  primera_fecha: string;
  ultima_fecha: string;
  emails_unicos: number;
  telefonos_unicos: number;
}

interface ClientesResponse {
  clientes: ClienteOpLead[];
  totalClientes: number;
  timestamp: string;
}

function ClienteCard({ cliente }: { cliente: ClienteOpLead }) {
  const formatDate = (dateString: string) => {
    try {
      return format(new Date(dateString), "dd/MM/yyyy", { locale: es });
    } catch {
      return dateString;
    }
  };

  return (
    <Card className="hover:shadow-lg transition-shadow duration-200" data-testid={`card-cliente-${cliente.cliente}`}>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2 text-lg" data-testid={`title-cliente-${cliente.cliente}`}>
            <Building className="h-5 w-5 text-blue-600" />
            {cliente.cliente}
          </CardTitle>
          <Badge variant="outline" className="bg-blue-50 text-blue-700 border-blue-200" data-testid={`badge-marca-${cliente.cliente}`}>
            {cliente.marca}
          </Badge>
        </div>
        <CardDescription className="flex items-center gap-1" data-testid={`location-${cliente.cliente}`}>
          <MapPin className="h-4 w-4" />
          {cliente.localizacion}
        </CardDescription>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Estadísticas principales */}
        <div className="grid grid-cols-2 gap-4">
          <div className="text-center p-3 bg-green-50 rounded-lg" data-testid={`total-leads-${cliente.cliente}`}>
            <div className="text-2xl font-bold text-green-700">{cliente.total_leads}</div>
            <div className="text-sm text-green-600 flex items-center justify-center gap-1">
              <Users className="h-4 w-4" />
              Total Leads
            </div>
          </div>

          <div className="space-y-2">
            <div className="flex items-center justify-between text-sm" data-testid={`emails-unicos-${cliente.cliente}`}>
              <span className="flex items-center gap-1">
                <Mail className="h-4 w-4 text-blue-500" />
                Emails únicos
              </span>
              <span className="font-medium">{cliente.emails_unicos}</span>
            </div>
            <div className="flex items-center justify-between text-sm" data-testid={`telefonos-unicos-${cliente.cliente}`}>
              <span className="flex items-center gap-1">
                <Phone className="h-4 w-4 text-green-500" />
                Teléfonos únicos
              </span>
              <span className="font-medium">{cliente.telefonos_unicos}</span>
            </div>
          </div>
        </div>

        {/* Fechas */}
        <div className="border-t pt-3 space-y-2">
          <div className="flex items-center justify-between text-sm" data-testid={`primera-fecha-${cliente.cliente}`}>
            <span className="flex items-center gap-1">
              <CalendarDays className="h-4 w-4 text-gray-500" />
              Primer lead
            </span>
            <span className="text-gray-600">{formatDate(cliente.primera_fecha)}</span>
          </div>
          <div className="flex items-center justify-between text-sm" data-testid={`ultima-fecha-${cliente.cliente}`}>
            <span className="flex items-center gap-1">
              <CalendarDays className="h-4 w-4 text-gray-500" />
              Último lead
            </span>
            <span className="text-gray-600">{formatDate(cliente.ultima_fecha)}</span>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function ClientesSkeleton() {
  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
      {Array.from({ length: 6 }).map((_, i) => (
        <Card key={i}>
          <CardHeader>
            <Skeleton className="h-6 w-3/4" />
            <Skeleton className="h-4 w-1/2" />
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <Skeleton className="h-16 w-full" />
              <div className="space-y-2">
                <Skeleton className="h-4 w-full" />
                <Skeleton className="h-4 w-full" />
              </div>
            </div>
            <div className="space-y-2">
              <Skeleton className="h-4 w-full" />
              <Skeleton className="h-4 w-full" />
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

export default function ClientesOpLeads() {
  const { data, isLoading, error } = useQuery<ClientesResponse>({
    queryKey: ['/api/op-leads/clientes'],
    refetchInterval: 30000, // Refrescar cada 30 segundos
  });

  if (isLoading) {
    return (
      <div className="container mx-auto p-6">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Clientes en OP Leads</h1>
          <p className="text-gray-600">Listado de todos los clientes presentes en la base de datos de leads</p>
        </div>
        <ClientesSkeleton />
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto p-6">
        <Card className="border-red-200 bg-red-50">
          <CardContent className="p-6">
            <div className="text-red-800">
              Error al cargar los clientes: {error instanceof Error ? error.message : 'Error desconocido'}
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  const clientes = data?.clientes || [];
  const totalClientes = data?.totalClientes || 0;
  const totalLeads = clientes.reduce((sum: number, cliente: ClienteOpLead) => sum + cliente.total_leads, 0);

  return (
    <div className="container mx-auto p-6">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2" data-testid="title-clientes-op-leads">
          Clientes en OP Leads
        </h1>
        <p className="text-gray-600 mb-4">
          Listado de todos los clientes presentes en la base de datos de leads
        </p>

        {/* Estadísticas globales */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <Card className="bg-blue-50 border-blue-200">
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-blue-700" data-testid="total-clientes-count">
                {totalClientes}
              </div>
              <div className="text-sm text-blue-600">Total Clientes</div>
            </CardContent>
          </Card>

          <Card className="bg-green-50 border-green-200">
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-green-700" data-testid="total-leads-count">
                {totalLeads.toLocaleString()}
              </div>
              <div className="text-sm text-green-600">Total Leads</div>
            </CardContent>
          </Card>

          <Card className="bg-purple-50 border-purple-200">
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-purple-700" data-testid="promedio-leads">
                {totalClientes > 0 ? Math.round(totalLeads / totalClientes) : 0}
              </div>
              <div className="text-sm text-purple-600">Promedio Leads/Cliente</div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Grid de clientes */}
      {clientes.length === 0 ? (
        <Card>
          <CardContent className="p-6 text-center">
            <Users className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-600">No se encontraron clientes en la base de datos</p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6" data-testid="grid-clientes">
          {clientes.map((cliente: ClienteOpLead) => (
            <ClienteCard key={`${cliente.cliente}-${cliente.marca}-${cliente.localizacion}`} cliente={cliente} />
          ))}
        </div>
      )}

      {/* Footer con timestamp */}
      <div className="mt-8 text-center text-sm text-gray-500" data-testid="timestamp">
        Última actualización: {data?.timestamp ? format(new Date(data.timestamp), "dd/MM/yyyy HH:mm:ss", { locale: es }) : 'No disponible'}
      </div>
    </div>
  );
}

