    --secondary: 215 16% 95%;
    --secondary-foreground: 215 25% 17%;
    --muted: 215 16% 97%;
    --muted-foreground: 215 16% 47%;
    --accent: 142 76% 36%; /* Success green */
    --accent-foreground: 0 0% 98%;
    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 98%;
    --border: 215 16% 92%;
    --input: 215 16% 95%;
