    --chart-1: 214 84% 56%; /* Primary blue */
    --chart-2: 142 76% 36%; /* Green */
    --chart-3: 45 93% 47%; /* Orange */
    --chart-4: 262 83% 58%; /* Purple */
    --chart-5: 346 87% 43%; /* Red */
    --chart-6: 189 85% 31%; /* Teal */
  }

  .dark {
    /* Modern Business Dashboard Theme - Dark */
    --background: 215 28% 7%;
    --foreground: 215 16% 94%;
    --card: 215 28% 10%;
    --card-foreground: 215 16% 94%;
    --popover: 215 28% 10%;
    --popover-foreground: 215 16% 94%;
    --primary: 214 84% 56%;
    --primary-foreground: 215 28% 7%;
    --secondary: 215 28% 14%;
    --secondary-foreground: 215 16% 94%;
    --muted: 215 28% 14%;
    --muted-foreground: 215 16% 65%;
    --accent: 142 76% 36%;
