server/sync/infrastructure/config/sync-c.content:
/**
 * Configuración específica para el sistema de sincronización
 * Centraliza todas las configuraciones relacionadas con sync
 */

export const SYNC_CONFIG = {
  // Configuración de procesamiento
  DEFAULT_BATCH_SIZE: 100,
  MAX_CONCURRENT_REQUESTS: 3,

  // Timeouts
  SYNC_TIMEOUT_MS: 10 * 60 * 1000, // 10 minutos
  SHEET_REQUEST_TIMEOUT_MS: 30 * 1000, // 30 segundos

  // Validación
  ENABLE_DATA_VALIDATION: true,
  ENABLE_DUPLICATE_DETECTION: true,

  // Logging
  ENABLE_DEBUG_LOGGING: process.env.NODE_ENV === 'development',
  LOG_SYNC_PERFORMANCE: true,

  // Sheets - DETECCIÓN AUTOMÁTICA (sin lista fija)
  // Las pestañas se detectan automáticamente usando Google Sheets API

  // Columnas de Google Sheets
  SHEET_COLUMNS: {
    TIMESTAMP: 'A',
    NAME: 'B',
    EMAIL: 'C',
    PHONE: 'D',
    CITY: 'E',
    INTEREST: 'F',
    ORIGEN: 'G',      // Nuevo: Origen del lead
    LOCALIZACION: 'H', // Nuevo: Ubicación geográfica
    CLIENTE: 'I'      // Nuevo: Cliente específico
  },

  // Filtros y exclusiones
  EXCLUDED_SHEETS: [
    'Datos Diarios',
    'Control Campañas',
    'Template',
    'Config'
  ],

  // Duplicados
  DUPLICATE_DETECTION_FIELDS: ['phone', 'metaLeadId'],
  SIMILARITY_THRESHOLD: 80, // Porcentaje

  // Performance
  MAX_LEADS_PER_SYNC: 10000,
  ENABLE_PARALLEL_PROCESSING: true,

  // Retry
  MAX_RETRY_ATTEMPTS: 3,
  RETRY_DELAY_MS: 1000,

  // Sync automático
  AUTO_SYNC_ENABLED: process.env.NODE_ENV === 'production',
  AUTO_SYNC_INTERVAL_MINUTES: 15,

  // Metadatos
  SYNC_VERSION: '2.0.0',
  LAST_MIGRATION_DATE: '2025-08-29'
} as const;

/**
 * Configuración específica por entorno
 */
export const getEnvironmentConfig = () => {
  const env = process.env.NODE_ENV || 'development';

  switch (env) {
    case 'production':
      return {
        ...SYNC_CONFIG,
        ENABLE_DEBUG_LOGGING: false,
        AUTO_SYNC_ENABLED: true,
        DEFAULT_BATCH_SIZE: 200,
        MAX_CONCURRENT_REQUESTS: 5
      };

    case 'test':
      return {
        ...SYNC_CONFIG,
        ENABLE_DEBUG_LOGGING: true,
        AUTO_SYNC_ENABLED: false,
        DEFAULT_BATCH_SIZE: 10,
        MAX_CONCURRENT_REQUESTS: 1,
        SYNC_TIMEOUT_MS: 5000
      };

    case 'development':
    default:
      return SYNC_CONFIG;
  }
};

/**
 * Utilidad para validar configuración
 */
export const validateConfig = (): boolean => {
  const config = getEnvironmentConfig();

  // Validaciones básicas
  if (config.DEFAULT_BATCH_SIZE <= 0) {
    console.error('❌ Config error: DEFAULT_BATCH_SIZE must be greater than 0');
    return false;
  }

  if (config.MAX_CONCURRENT_REQUESTS <= 0) {
    console.error('❌ Config error: MAX_CONCURRENT_REQUESTS must be greater than 0');
    return false;
  }

  // NOTA: Ya no validamos AVAILABLE_SHEETS porque se detectan automáticamente
  // Las pestañas se obtienen dinámicamente de Google Sheets API

  console.log('✅ Sync configuration validated successfully');
  return true;
};

/**
 * Configuración de logging para sync
 */
export const SYNC_LOGGER_CONFIG = {
  levels: {
    ERROR: 0,
    WARN: 1,
    INFO: 2,
    DEBUG: 3
  },

  currentLevel: SYNC_CONFIG.ENABLE_DEBUG_LOGGING ? 3 : 2,

  formatters: {
    sync: (message: string) => `🔄 SYNC: ${message}`,
    error: (message: string) => `❌ SYNC ERROR: ${message}`,
    success: (message: string) => `✅ SYNC SUCCESS: ${message}`,
    warn: (message: string) => `⚠️ SYNC WARNING: ${message}`,
    info: (message: string) => `ℹ️ SYNC INFO: ${message}`
  }
};

/**
 * Log helper específico para sync
 */
export const syncLogger = {
  error: (message: string, ...args: any[]) => {
    if (SYNC_LOGGER_CONFIG.currentLevel >= 0) {
      console.error(SYNC_LOGGER_CONFIG.formatters.error(message), ...args);
    }
  },

  warn: (message: string, ...args: any[]) => {
    if (SYNC_LOGGER_CONFIG.currentLevel >= 1) {
      console.warn(SYNC_LOGGER_CONFIG.formatters.warn(message), ...args);
    }
  },

  info: (message: string, ...args: any[]) => {
    if (SYNC_LOGGER_CONFIG.currentLevel >= 2) {
      console.info(SYNC_LOGGER_CONFIG.formatters.info(message), ...args);
    }
  },

  debug: (message: string, ...args: any[]) => {
    if (SYNC_LOGGER_CONFIG.currentLevel >= 3) {
      console.log(SYNC_LOGGER_CONFIG.formatters.sync(message), ...args);
    }
  },

  success: (message: string, ...args: any[]) => {
    console.log(SYNC_LOGGER_CONFIG.formatters.success(message), ...args);
  }
};

client/src/components/leads/ReassignLead.content:
import { useState, useEffect } from "react";

interface Props {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  selectedLeadIds: number[];
  onConfirm: (clienteSeleccionado: string) => Promise<void>;
}

export function ReassignLeadsDialog({
  open,
  onOpenChange,
  selectedLeadIds,
  onConfirm,
}: Props) {
  const [clientes, setClientes] = useState<string[]>([]);
  const [clienteSeleccionado, setClienteSeleccionado] = useState<string>("");
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Cargar lista de clientes cuando se abre el diálogo
  useEffect(() => {
    if (open) {
      fetchClientes();
      setClienteSeleccionado("");
      setError(null);
    }
  }, [open]);

  const fetchClientes = async () => {
    setLoading(true);
    try {
      const response = await fetch("/api/clients");
      if (!response.ok) throw new Error("Error al cargar clientes");
      const data = await response.json();
      setClientes(data || []);
    } catch (err: any) {
      console.error("Error cargando clientes:", err);
      setError("Error al cargar la lista de clientes");
      setClientes([]);
    } finally {
      setLoading(false);
    }
  };

  const handleConfirm = async () => {
    if (!clienteSeleccionado) {
      setError("Por favor selecciona un cliente");
      return;
    }

    setSubmitting(true);
    setError(null);

    try {
      await onConfirm(clienteSeleccionado);
      // Si llega aquí, fue exitoso
      onOpenChange(false);
    } catch (err: any) {
      setError(err.message || "Error al reasignar leads");
    } finally {
      setSubmitting(false);
    }
  };

  const handleCancel = () => {
    setClienteSeleccionado("");
    setError(null);
    onOpenChange(false);
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-2xl p-6 w-full max-w-md mx-4">
        {/* Header */}
        <h2 className="text-xl font-bold text-gray-900 mb-4">
          Reasignar leads
        </h2>

        <div className="space-y-4">
          {/* Contador de leads seleccionados */}
          <div className="bg-blue-50 border-2 border-blue-200 rounded-lg p-3">
            <p className="text-sm text-gray-700">
              Leads seleccionados:{" "}
              <span className="font-bold text-blue-700 text-lg">
                {selectedLeadIds.length}
              </span>
            </p>
          </div>

          {/* Selector de cliente */}
          <div>
            <label
              htmlFor="cliente-select"
              className="block text-sm font-semibold text-gray-700 mb-2"
            >
              Reasignar a cliente: <span className="text-red-500">*</span>
            </label>
            <select
              id="cliente-select"
              value={clienteSeleccionado}
              onChange={(e) => {
                setClienteSeleccionado(e.target.value);
                setError(null);
              }}
              disabled={loading || submitting}
              className="w-full px-4 py-2.5 border-2 border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none disabled:bg-gray-100 disabled:cursor-not-allowed transition-all"
            >
              <option value="">
                {loading ? "Cargando clientes..." : "Selecciona un cliente"}
              </option>
              {clientes.map((cliente) => (
                <option key={cliente} value={cliente}>
                  {cliente}
                </option>
              ))}
            </select>
          </div>

          {/* Mensaje de error */}
          {error && (
            <div className="bg-red-50 border-2 border-red-200 rounded-lg p-3 animate-shake">
              <p className="text-sm text-red-700 font-medium">⚠️ {error}</p>
            </div>
          )}

          {/* Info adicional */}
          {clientes.length > 0 && !loading && (
            <div className="bg-gray-50 border border-gray-200 rounded-lg p-3">
              <p className="text-xs text-gray-600 mb-2">
                📋 Clientes disponibles:{" "}
                <span className="font-semibold">{clientes.length}</span>
              </p>
              <div className="flex flex-wrap gap-1.5">
                {clientes.slice(0, 6).map((cliente) => (
                  <span
                    key={cliente}
                    className="inline-block px-2 py-1 bg-white border border-gray-200 text-gray-700 text-xs rounded-md shadow-sm"
                  >
                    {cliente}
                  </span>
                ))}
                {clientes.length > 6 && (
                  <span className="inline-block px-2 py-1 bg-blue-50 border border-blue-200 text-blue-700 text-xs rounded-md font-medium">
                    +{clientes.length - 6} más
                  </span>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Botones de acción */}
        <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-200">
          <button
            onClick={handleCancel}
            disabled={submitting}
            className="px-5 py-2.5 text-gray-700 bg-white border-2 border-gray-300 hover:bg-gray-50 rounded-lg font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Cancelar
          </button>
          <button
            onClick={handleConfirm}
            disabled={!clienteSeleccionado || loading || submitting}
            className="px-5 py-2.5 text-white bg-blue-600 hover:bg-blue-700 rounded-lg font-medium transition-all disabled:bg-gray-300 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {submitting ? (
              <>
                <span className="animate-spin h-4 w-4 border-2 border-white rounded-full border-t-transparent"></span>
                Reasignando...
              </>
            ) : (
              "Confirmar"
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

client/src/hooks/use-toast.ts.content:
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

